	private TupleExpr antiExistsProbe(ValueExpr condition) {
		if (condition instanceof Not not && not.getArg()instanceof Exists exists) {
			return exists.getSubQuery();
		}
		return null;
	}

	private TupleExpr existsProbe(ValueExpr condition) {
		if (condition instanceof Exists exists) {
			return exists.getSubQuery();
		}
		return null;
	}

	private StatementPattern correlatedAntiExistsPrefixPattern(List<TupleExpr> prefixFactors,
			Set<String> antiProbeBindings) {
		if (prefixFactors == null || prefixFactors.isEmpty()
				|| antiProbeBindings == null || antiProbeBindings.isEmpty()) {
			return null;
		}
		for (TupleExpr prefixFactor : prefixFactors) {
			StatementPattern pattern = simpleStatementPattern(prefixFactor);
			if (pattern == null) {
				continue;
			}
			Set<String> sharedBindings = plannerBindingNames(pattern.getAssuredBindingNames());
			sharedBindings.retainAll(antiProbeBindings);
			if (sharedBindings.size() == 1) {
				return pattern;
			}
		}
		return null;
	}

	private StatementPattern simpleStatementPattern(TupleExpr tupleExpr) {
		TupleExpr current = tupleExpr;
		while (current instanceof Filter filter) {
			current = filter.getArg();
		}
		return current instanceof StatementPattern statementPattern ? statementPattern : null;
	}

	private StatisticsEstimate correlatedAntiExistsExactStatisticsEstimate(StatisticsEstimate inputEstimate,
			StatisticsEstimate filteredEstimate, CorrelatedAntiExistsExactEstimate exactEstimate) {
		double workRows = filteredEstimate.workRows() + exactEstimate.probeWorkRows();
		Map<String, Double> metrics = new HashMap<>(filteredEstimate.metrics());
		metrics.put("plannedAntiExistsProbeWorkRows", exactEstimate.probeWorkRows());
		metrics.put("plannedAntiExistsProbeOutputRows", exactEstimate.probeOutputRows());
		metrics.put("plannedAntiExistsMatchedRows", exactEstimate.matchedRows());
		metrics.put("plannedAntiExistsInputRows", inputEstimate.rows());
		metrics.put("plannedAntiExistsSharedBindingCount", 1.0d);
		metrics.put("plannedAntiExistsExactInputRows", exactEstimate.inputRows());
		metrics.put("plannedAntiExistsExactProbeRows", exactEstimate.probeOutputRows());
		metrics.put("plannedAntiExistsExactProbeLookupRows", exactEstimate.probeLookupRows());
		metrics.put("plannedAntiExistsExactRhsRowsScanned", exactEstimate.rhsRowsScanned());
		metrics.put("plannedAntiExistsExactWorkRows", exactEstimate.probeWorkRows());
		metrics.put(TelemetryMetricNames.PLANNED_WORK_ROWS, workRows);
		metrics.put(TelemetryMetricNames.PLANNED_COST_WORK_ROWS, workRows);
		BagEstimate bag = filteredEstimate.bag()
				.withRows(exactEstimate.outputRows(), "lmdb-correlated-anti-exists-exact-probe")
				.withWorkRows(workRows, "lmdb-correlated-anti-exists-exact-probe")
				.withMetrics(metrics);
		QErrorInterval interval = QErrorInterval.heuristic(exactEstimate.outputRows(),
				filteredEstimate.qErrorInterval().qError(), "lmdb-correlated-anti-exists-exact-probe");
		return new StatisticsEstimate(exactEstimate.outputRows(), interval,
				workRows, "lmdb-correlated-anti-exists-exact-probe", metrics, bag);
	}

	private CorrelatedAntiExistsExactEstimate estimateExactCorrelatedAntiExists(TupleExpr input, TupleExpr antiProbe,
			double inputRows, Set<String> sharedBindings) {
		if (tripleStore == null || valueStore == null || !(input instanceof StatementPattern inputPattern)
				|| !isFiniteNonNegative(inputRows)
				|| inputRows > CORRELATED_ANTI_EXISTS_EXACT_MAX_INPUT_ROWS
				|| sharedBindings == null || sharedBindings.size() != 1) {
			return null;
		}
		CorrelatedAntiProbePattern antiPattern = correlatedAntiProbePattern(antiProbe);
		if (antiPattern == null) {
			return null;
		}
		String sharedBinding = sharedBindings.iterator().next();
		Component inputSharedComponent = singleVariableComponent(inputPattern, sharedBinding);
		Component antiSharedComponent = singleVariableComponent(antiPattern.pattern(), sharedBinding);
		if (inputSharedComponent == null || antiSharedComponent == null
				|| !conditionUsesOnlyPatternBindings(antiPattern.condition(), antiPattern.pattern())) {
			return null;
		}
		// The scan below is fully determined by the two patterns, the condition and the committed store
		// state; the inputRows argument only gates entry above. Cache after that gate so repeated planning
		// contexts (one per candidate join prefix) don't re-execute the anti-join.
		CorrelatedAntiExistsExactCacheKey cacheKey = new CorrelatedAntiExistsExactCacheKey(
				System.identityHashCode(tripleStore), tripleStore.getDataRevision(),
				factorFingerprint(inputPattern), factorFingerprint(antiProbe), sharedBinding);
		Optional<CorrelatedAntiExistsExactEstimate> cached = CORRELATED_ANTI_EXISTS_EXACT_CACHE.get(cacheKey);
		if (cached != null) {
			return cached.orElse(null);
		}
		DefaultEvaluationStrategy strategy = exactFilterEvaluationStrategy();
		QueryValueEvaluationStep condition = antiPattern.condition() == null
				? null
				: prepareExactFilterCondition(strategy, antiPattern.condition());
		if (antiPattern.condition() != null && condition == null) {
			return null;
		}
		try (Txn txn = tripleStore.getTxnManager().createReadTxn()) {
			PatternIds inputIds = patternIds(inputPattern, null, LmdbValue.UNKNOWN_ID);
			if (inputIds == null || inputIds.zeroRows()) {
				return cacheExactCorrelatedAntiExists(cacheKey, null);
			}
			Map<Long, Boolean> antiMatches = new HashMap<>();
			long inputRowsScanned = 0L;
			long matchedRows = 0L;
			long rhsRowsScanned = 0L;
			long probeLookupRows = 0L;
			for (boolean explicit : new boolean[] { true, false }) {
				try (RecordIterator records = tripleStore.getTriples(txn, inputIds.subjectId(),
						inputIds.predicateId(), inputIds.objectId(), inputIds.contextId(), explicit)) {
					long[] row;
					while ((row = records.next()) != null) {
						if (!matchesRepeatedVariableEquality(inputPattern, row)) {
							continue;
						}
						inputRowsScanned++;
						if (inputRowsScanned > CORRELATED_ANTI_EXISTS_EXACT_MAX_INPUT_ROWS) {
							return cacheExactCorrelatedAntiExists(cacheKey, null);
						}
						long sharedId = row[inputSharedComponent.ordinal()];
						Boolean matched = antiMatches.get(sharedId);
						if (matched == null) {
							CorrelatedAntiProbeResult result = exactAntiProbeMatches(txn, antiPattern.pattern(),
									condition, strategy, sharedBinding, sharedId);
							if (result == null) {
								return cacheExactCorrelatedAntiExists(cacheKey, null);
							}
							rhsRowsScanned += result.rhsRowsScanned();
							probeLookupRows++;
							if (probeLookupRows + rhsRowsScanned > CORRELATED_ANTI_EXISTS_EXACT_MAX_WORK_ROWS) {
								return cacheExactCorrelatedAntiExists(cacheKey, null);
							}
							matched = result.matched();
							antiMatches.put(sharedId, matched);
						}
						if (matched) {
							matchedRows++;
						}
					}
				}
			}
			if (inputRowsScanned == 0L) {
				return cacheExactCorrelatedAntiExists(cacheKey, new CorrelatedAntiExistsExactEstimate(0.0d, 0.0d,
						0.0d, probeLookupRows, rhsRowsScanned, probeLookupRows + rhsRowsScanned));
			}
			double outputRows = Math.max(0.0d, inputRowsScanned - matchedRows);
			double probeOutputRows = matchedRows;
			double probeWorkRows = Math.max(probeLookupRows, probeLookupRows + rhsRowsScanned);
			return cacheExactCorrelatedAntiExists(cacheKey, new CorrelatedAntiExistsExactEstimate(inputRowsScanned,
					matchedRows, outputRows, probeLookupRows, rhsRowsScanned,
					Math.max(probeWorkRows, probeOutputRows)));
		} catch (IOException | RuntimeException e) {
			// Not cached: exceptions are not a deterministic function of the store state.
			return null;
		}
	}

	private CorrelatedAntiExistsExactEstimate cacheExactCorrelatedAntiExists(CorrelatedAntiExistsExactCacheKey key,
			CorrelatedAntiExistsExactEstimate estimate) {
		if (CORRELATED_ANTI_EXISTS_EXACT_CACHE.size() >= CORRELATED_ANTI_EXISTS_EXACT_CACHE_MAX_ENTRIES) {
			CORRELATED_ANTI_EXISTS_EXACT_CACHE.clear();
		}
		CORRELATED_ANTI_EXISTS_EXACT_CACHE.put(key, Optional.ofNullable(estimate));
		return estimate;
	}

	private CorrelatedAntiProbeResult exactAntiProbeMatches(Txn txn, StatementPattern pattern,
			QueryValueEvaluationStep condition, DefaultEvaluationStrategy strategy, String sharedBinding,
			long sharedId) throws IOException {
		PatternIds ids = patternIds(pattern, sharedBinding, sharedId);
		if (ids == null) {
			return null;
		}
		if (ids.zeroRows()) {
			return new CorrelatedAntiProbeResult(false, 0L);
		}
		long rhsRowsScanned = 0L;
		for (boolean explicit : new boolean[] { true, false }) {
			try (RecordIterator records = tripleStore.getTriples(txn, ids.subjectId(), ids.predicateId(),
					ids.objectId(), ids.contextId(), explicit)) {
				long[] row;
				while ((row = records.next()) != null) {
					if (!matchesRepeatedVariableEquality(pattern, row)) {
						continue;
					}
					rhsRowsScanned++;
					if (condition == null || exactFilterConditionMatches(condition, strategy, pattern, row)) {
						return new CorrelatedAntiProbeResult(true, rhsRowsScanned);
					}
				}
			}
		}
		return new CorrelatedAntiProbeResult(false, rhsRowsScanned);
	}

	private CorrelatedAntiProbePattern correlatedAntiProbePattern(TupleExpr antiProbe) {
		if (antiProbe instanceof StatementPattern pattern) {
			return new CorrelatedAntiProbePattern(pattern, null);
		}
		if (antiProbe instanceof Filter filter && filter.getArg()instanceof StatementPattern pattern) {
			return new CorrelatedAntiProbePattern(pattern, filter.getCondition());
		}
		return null;
	}

	private boolean exactFilterConditionMatches(QueryValueEvaluationStep condition, DefaultEvaluationStrategy strategy,
			StatementPattern pattern, long[] row) throws IOException {
		BindingSet bindingSet = toBindingSet(pattern, row);
		try {
			return strategy.isTrue(condition, bindingSet);
		} catch (ValueExprEvaluationException e) {
			return false;
		} catch (QueryEvaluationException e) {
			return false;
		}
	}

	private QueryValueEvaluationStep prepareExactFilterCondition(DefaultEvaluationStrategy strategy,
			ValueExpr condition) {
		try {
			return strategy.precompile(condition, new QueryEvaluationContext.Minimal(null, valueStore, null));
		} catch (RuntimeException e) {
			return null;
		}
	}

	private DefaultEvaluationStrategy exactFilterEvaluationStrategy() {
		return new DefaultEvaluationStrategy(new TripleSource() {
			@Override
			public CloseableIteration<? extends Statement> getStatements(Resource subj, IRI pred, Value obj,
					Resource... contexts) throws QueryEvaluationException {
				return TripleSource.EMPTY_ITERATION;
			}

			@Override
			public CloseableIteration<? extends Statement> getStatements(StatementOrder order, Resource subj,
					IRI pred, Value obj, Resource... contexts) throws QueryEvaluationException {
				return TripleSource.EMPTY_ITERATION;
			}

			@Override
			public ValueFactory getValueFactory() {
				return valueStore;
			}
		}, null);
	}

	private boolean conditionUsesOnlyPatternBindings(ValueExpr condition, StatementPattern pattern) {
		if (condition == null) {
			return true;
		}
		Set<String> bindingNames = plannerBindingNames(pattern.getBindingNames());
		boolean[] supported = { true };
		condition.visit(new AbstractQueryModelVisitor<RuntimeException>() {
			@Override
			public void meet(Var var) {
				if (!supported[0] || var.hasValue() || var.getName() == null) {
					return;
				}
				if (!bindingNames.contains(var.getName())) {
					supported[0] = false;
				}
			}

			@Override
			public void meet(Exists exists) {
				supported[0] = false;
			}
		});
		return supported[0];
	}

	private BindingSet toBindingSet(StatementPattern pattern, long[] row) throws IOException {
		MapBindingSet bindingSet = new MapBindingSet(4);
		addBinding(bindingSet, pattern.getSubjectVar(), row[TripleStore.SUBJ_IDX]);
		addBinding(bindingSet, pattern.getPredicateVar(), row[TripleStore.PRED_IDX]);
		addBinding(bindingSet, pattern.getObjectVar(), row[TripleStore.OBJ_IDX]);
		addBinding(bindingSet, pattern.getContextVar(), row[TripleStore.CONTEXT_IDX]);
		return bindingSet;
	}

	private void addBinding(MapBindingSet bindingSet, Var var, long valueId) throws IOException {
		if (var == null || var.hasValue() || var.getName() == null || bindingSet.hasBinding(var.getName())
				|| valueId == 0L) {
			return;
		}
		bindingSet.addBinding(var.getName(), valueStore.getValue(valueId));
	}

	private PatternIds patternIds(StatementPattern pattern, String boundVarName, long boundVarId) throws IOException {
		long subjectId = patternComponentId(pattern.getSubjectVar(), Component.S, boundVarName, boundVarId);
		if (subjectId == Long.MIN_VALUE) {
			return PatternIds.ZERO_ROWS;
		}
		long predicateId = patternComponentId(pattern.getPredicateVar(), Component.P, boundVarName, boundVarId);
		if (predicateId == Long.MIN_VALUE) {
			return PatternIds.ZERO_ROWS;
		}
		long objectId = patternComponentId(pattern.getObjectVar(), Component.O, boundVarName, boundVarId);
		if (objectId == Long.MIN_VALUE) {
			return PatternIds.ZERO_ROWS;
		}
		long contextId = patternComponentId(pattern.getContextVar(), Component.C, boundVarName, boundVarId);
		if (contextId == Long.MIN_VALUE) {
			return PatternIds.ZERO_ROWS;
		}
		return new PatternIds(subjectId, predicateId, objectId, contextId);
	}

	private long patternComponentId(Var var, Component component, String boundVarName, long boundVarId)
			throws IOException {
		if (var == null) {
			return LmdbValue.UNKNOWN_ID;
		}
		if (var.hasValue()) {
			Value value = var.getValue();
			if (!isValidLookupValue(component, value)) {
				return Long.MIN_VALUE;
			}
			long id = valueStore.getId(value);
			return id == LmdbValue.UNKNOWN_ID ? Long.MIN_VALUE : id;
		}
		if (boundVarName != null && boundVarName.equals(var.getName())) {
			return boundVarId;
		}
		return LmdbValue.UNKNOWN_ID;
	}

	private Component singleVariableComponent(StatementPattern pattern, String variableName) {
		Component match = null;
		for (Component component : Component.values()) {
			Var var = componentVar(pattern, component);
			if (var == null || var.hasValue() || var.getName() == null || !var.getName().equals(variableName)) {
				continue;
			}
			if (match != null) {
				return null;
			}
			match = component;
		}
		return match;
	}

	private boolean matchesRepeatedVariableEquality(StatementPattern pattern, long[] row) {
		Map<String, Long> bindingsByName = new HashMap<>(4);
		return matchesRepeatedVariable(pattern.getSubjectVar(), row[TripleStore.SUBJ_IDX], bindingsByName)
				&& matchesRepeatedVariable(pattern.getPredicateVar(), row[TripleStore.PRED_IDX], bindingsByName)
				&& matchesRepeatedVariable(pattern.getObjectVar(), row[TripleStore.OBJ_IDX], bindingsByName)
				&& matchesRepeatedVariable(pattern.getContextVar(), row[TripleStore.CONTEXT_IDX], bindingsByName);
	}

	private boolean matchesRepeatedVariable(Var var, long valueId, Map<String, Long> bindingsByName) {
		if (var == null || var.hasValue() || var.getName() == null) {
			return true;
		}
		Long existing = bindingsByName.putIfAbsent(var.getName(), valueId);
		return existing == null || existing.longValue() == valueId;
	}

	private TupleExpr leftDeepJoin(List<TupleExpr> orderedFactors) {
		TupleExpr root = orderedFactors.getFirst().clone();
		for (int i = 1; i < orderedFactors.size(); i++) {
			root = new Join(root, orderedFactors.get(i).clone());
		}
		return root;
	}

	@Override
	public Optional<StatisticsEstimate> characteristicSetStar(List<StatementPattern> starPatterns,
			Set<String> boundVars) {
		Optional<CharacteristicSetEstimate> estimate = estimateSubjectStar(starPatterns,
				boundVars == null ? Set.of() : boundVars);
		if (estimate.isEmpty()) {
			return Optional.empty();
		}
		CharacteristicSetEstimate characteristicSet = estimate.get();
		if (characteristicSet.rows() == 0.0d && characteristicSet.scannedRows() == 0L) {
			traceStarMultiPredicateScan("characteristic-set-star-reject", starPatterns, boundVars,
					"reason=sketch-only-zero, method=" + characteristicSet.method());
			return Optional.empty();
		}
		return Optional.of(new StatisticsEstimate(characteristicSet.rows(),
				QErrorInterval.heuristic(characteristicSet.rows(), 2.0d, "lmdb-characteristic-set"),
				Math.max(characteristicSet.rows(), characteristicSet.scannedRows()), "lmdb-characteristic-set",
				Map.of("subjectCount", (double) characteristicSet.subjectCount(),
						"sketchOnlyStatementScans", (double) characteristicSet.scannedRows())));
	}

	@Override
	public Optional<StatisticsEstimate> propertyPathNodePairs(TupleExpr path, Set<String> boundVars) {
		Optional<PropertyPathEstimate> estimate = Optional.empty();
		Set<String> effectiveBoundVars = boundVars == null ? Set.of() : boundVars;
		if (path instanceof ArbitraryLengthPath arbitraryLengthPath) {
			estimate = estimatePropertyPath(arbitraryLengthPath, effectiveBoundVars);
		} else if (path instanceof ZeroLengthPath zeroLengthPath) {
			estimate = estimatePropertyPath(zeroLengthPath, effectiveBoundVars);
		}
		return estimate.map(value -> {
			PropertyPathEstimate adjusted = adjustPropertyPathEstimate(path, effectiveBoundVars, value);
			String endpointMode = propertyPathEndpointMode(path, effectiveBoundVars);
			double rows = adjusted.rows();
			double workRows = adjusted.workRows();
			String source = adjusted.method();
			double qErrorMax = 3.0d;
			Map<String, Double> metrics = new HashMap<>();
			metrics.put("distinctSubjects", adjusted.distinctSubjects());
			metrics.put("distinctObjects", adjusted.distinctObjects());
			metrics.put("averagePathFanout", adjusted.averagePathFanout());
			metrics.put("workRows", adjusted.workRows());

			LmdbOperatorFeedbackStats.OperatorEstimate feedback = estimateOperatorFeedback(path, Double.NaN,
					Double.NaN, rows, workRows, endpointMode);
			if (feedback != null) {
				rows = feedback.rows();
				workRows = robustFeedbackWorkRows(feedback);
				source = feedback.source();
				qErrorMax = Math.max(feedback.rowQErrorMax(), feedback.workQErrorMax());
				metrics.put("plannedBaseRows", adjusted.rows());
				metrics.put("plannedBaseWorkRows", adjusted.workRows());
				metrics.put("plannedOperatorFeedbackRows", feedback.rows());
				metrics.put("plannedOperatorFeedbackWorkRows", feedback.workRows());
				metrics.put(PLANNED_OPERATOR_FEEDBACK_ROBUST_WORK_ROWS, workRows);
				metrics.put("plannedOperatorFeedbackEvidence", (double) feedback.evidenceCount());
				metrics.put("plannedOperatorFeedbackConfidence", feedback.confidence());
				metrics.put(PLANNED_OPERATOR_FEEDBACK_CORRECTION_CONFIDENCE, feedback.correctionConfidence());
				metrics.put(PLANNED_OPERATOR_FEEDBACK_ROW_Q_ERROR_MEAN, feedback.rowQErrorMean());
				metrics.put(PLANNED_OPERATOR_FEEDBACK_ROW_Q_ERROR_MAX, feedback.rowQErrorMax());
				metrics.put(PLANNED_OPERATOR_FEEDBACK_WORK_Q_ERROR_MEAN, feedback.workQErrorMean());
				metrics.put(PLANNED_OPERATOR_FEEDBACK_WORK_Q_ERROR_MAX, feedback.workQErrorMax());
				metrics.put(PLANNED_OPERATOR_FEEDBACK_UNCERTAINTY_ROWS, feedback.uncertaintyRows());
			}

			workRows = Math.max(rows, workRows);
			return new StatisticsEstimate(rows, QErrorInterval.heuristic(rows, qErrorMax, source), workRows, source,
					metrics);
		});
	}

	private PropertyPathEstimate adjustPropertyPathEstimate(TupleExpr path, Set<String> boundVars,
			PropertyPathEstimate estimate) {
		if (path == null || estimate == null) {
			return estimate;
		}
		Var subjectVar = null;
		Var objectVar = null;
		if (path instanceof ArbitraryLengthPath arbitraryLengthPath) {
			subjectVar = arbitraryLengthPath.getSubjectVar();
			objectVar = arbitraryLengthPath.getObjectVar();
		} else if (path instanceof ZeroLengthPath zeroLengthPath) {
			subjectVar = zeroLengthPath.getSubjectVar();
			objectVar = zeroLengthPath.getObjectVar();
		}
		boolean subjectBound = pathEndpointBound(subjectVar, boundVars);
		boolean objectBound = pathEndpointBound(objectVar, boundVars);
		if (!subjectBound && !objectBound) {
			return estimate;
		}
		double rows = estimate.rows();
		double workRows = estimate.workRows();
		if (path instanceof ArbitraryLengthPath) {
			if (!isFiniteNonNegative(workRows)) {
				workRows = rows;
			}
			String endpointMode = propertyPathEndpointMode(path, boundVars);
			return new PropertyPathEstimate(rows, Math.max(rows, workRows), estimate.distinctSubjects(),
					estimate.distinctObjects(), estimate.averagePathFanout(), estimate.method() + "-" + endpointMode);
		}
		if (subjectBound && isPositiveFinite(estimate.distinctSubjects())) {
			rows = Math.min(rows, Math.max(1.0d, estimate.rows() / estimate.distinctSubjects()));
		}
		if (objectBound && isPositiveFinite(estimate.distinctObjects())) {
			rows = Math.min(rows, Math.max(1.0d, estimate.rows() / estimate.distinctObjects()));
		}
		if (subjectBound && objectBound) {
			rows = Math.min(rows, Math.max(1.0d, estimate.averagePathFanout()));
		}
		if (!isFiniteNonNegative(workRows)) {
			workRows = rows;
		}
		String endpointMode = propertyPathEndpointMode(path, boundVars);
		return new PropertyPathEstimate(rows, Math.max(rows, workRows), estimate.distinctSubjects(),
				estimate.distinctObjects(), estimate.averagePathFanout(), estimate.method() + "-" + endpointMode);
	}

	private boolean pathEndpointBound(Var var, Set<String> boundVars) {
		if (var == null) {
			return false;
		}
		if (var.hasValue()) {
			return true;
		}
		String name = var.getName();
		return name != null && !name.startsWith("_const_") && boundVars != null && boundVars.contains(name);
	}

	private String propertyPathEndpointMode(TupleExpr path, Set<String> boundVars) {
		Var subjectVar = null;
		Var objectVar = null;
		if (path instanceof ArbitraryLengthPath arbitraryLengthPath) {
			subjectVar = arbitraryLengthPath.getSubjectVar();
			objectVar = arbitraryLengthPath.getObjectVar();
		} else if (path instanceof ZeroLengthPath zeroLengthPath) {
			subjectVar = zeroLengthPath.getSubjectVar();
			objectVar = zeroLengthPath.getObjectVar();
		}
		boolean subjectBound = pathEndpointBound(subjectVar, boundVars);
		boolean objectBound = pathEndpointBound(objectVar, boundVars);
		if (subjectBound && objectBound) {
			return PATH_MODE_BETWEEN;
		}
		if (subjectBound) {
			return PATH_MODE_FROM_START;
		}
		if (objectBound) {
			return PATH_MODE_TO_END;
		}
		return PATH_MODE_FULL_SCAN;
	}

	private String operatorFeedbackExecutionMode(TupleExpr factor, JoinFactorCostModel.CostContext context) {
		if (factor instanceof ArbitraryLengthPath || factor instanceof ZeroLengthPath) {
			Set<String> boundVars = context == null ? Set.of() : context.getCurrentlyBoundVars();
			return propertyPathEndpointMode(factor, boundVars);
		}
		return null;
	}

	@Override
	public Optional<FeedbackCorrection> feedbackCorrection(TupleExpr tupleExpr, StatisticsEstimate baseEstimate) {
		if (tupleExpr == null || baseEstimate == null) {
			return Optional.empty();
		}
		String executionMode = tupleExpr.getStringMetricPlanned(PLANNED_PROPERTY_PATH_ENDPOINT_MODE);
		if (executionMode == null) {
			executionMode = tupleExpr.getStringMetricPlanned(OPTIMIZER_PATH_ENDPOINT_MODE);
		}
		LmdbOperatorFeedbackStats.OperatorEstimate estimate = estimateOperatorFeedback(tupleExpr, Double.NaN,
				Double.NaN,
				baseEstimate.rows(), baseEstimate.workRows(), executionMode);
		if (estimate == null) {
			return Optional.empty();
		}
		return Optional.of(new FeedbackCorrection(estimate.rows(), estimate.workRows(),
				estimate.correctionConfidence(), estimate.rowQErrorMax(), estimate.workQErrorMax(),
				estimate.source()));
	}

	private QErrorInterval qErrorIntervalFromMetrics(double rows, Map<String, Double> metrics, String source) {
		if (metrics == null || metrics.isEmpty()) {
			return QErrorInterval.heuristic(rows, 3.0d, source == null ? "lmdb" : source);
		}
		double lower = metrics.getOrDefault(TelemetryMetricNames.PLANNED_CARDINALITY_LOWER, Double.NaN);
		double upper = metrics.getOrDefault(TelemetryMetricNames.PLANNED_CARDINALITY_UPPER, Double.NaN);
		double confidence = metrics.getOrDefault(TelemetryMetricNames.PLANNED_CARDINALITY_CONFIDENCE, 0.5d);
		if (isFiniteNonNegative(lower) && isFiniteNonNegative(upper) && upper >= lower) {
			return QErrorInterval.fromBounds(lower, rows, upper, confidence, source == null ? "lmdb" : source);
		}
		double qError = metrics.getOrDefault(PLANNED_OPERATOR_FEEDBACK_ROW_Q_ERROR_MAX, 3.0d);
		return QErrorInterval.heuristic(rows, qError, source == null ? "lmdb" : source);
	}

	@Override
	public QueryOptimizationScope beginQueryOptimizationScope() {
		QueryOptimizationScope sketchScope = sketchBasedJoinEstimator == null
				? QueryOptimizationScopeProvider.NO_OP_SCOPE
				: sketchBasedJoinEstimator.beginQueryOptimizationScope();
		OptimizationCostScope costScope = optimizationCostScope.get();
		if (costScope == null) {
			costScope = new OptimizationCostScope();
			optimizationCostScope.set(costScope);
		}
		costScope.depth++;
		return () -> {
			try {
				sketchScope.close();
			} finally {
				closeOptimizationCostScope();
			}
		};
	}

	private void closeOptimizationCostScope() {
		OptimizationCostScope costScope = optimizationCostScope.get();
		if (costScope == null) {
			return;
		}
		costScope.depth--;
		if (costScope.depth <= 0) {
			optimizationCostScope.remove();
		}
	}

	boolean hasOptimizationScopedPlannerCache() {
		return optimizationCostScope.get() != null;
	}

	Object getOptimizationScopedPlannerCacheValue(Object key) {
		OptimizationCostScope costScope = optimizationCostScope.get();
		if (costScope == null || key == null) {
			return null;
		}
		return costScope.plannerCache.get(key);
	}

	void putOptimizationScopedPlannerCacheValue(Object key, Object value) {
		OptimizationCostScope costScope = optimizationCostScope.get();
		if (costScope != null && key != null && value != null) {
			costScope.plannerCache.put(key, value);
		}
	}

	Object optimizationScopedFactorFingerprint(TupleExpr factor) {
		return factorFingerprint(factor);
	}

	@Override
	public Optional<JoinOrderPlan> planJoinOrder(List<TupleExpr> args, Set<String> initiallyBoundVars,
			Algorithm algorithm) {
		return planJoinOrder(args, initiallyBoundVars, algorithm, List.of());
	}

	@Override
	public Optional<JoinOrderPlan> planJoinOrder(List<TupleExpr> args, Set<String> initiallyBoundVars,
			Algorithm algorithm, List<FilterConstraint> deferredFilters) {
		return planJoinOrderAttempt(args, initiallyBoundVars, algorithm, deferredFilters).getPlan();
	}

	@Override
	public PlanningAttempt planJoinOrderAttempt(List<TupleExpr> args, Set<String> initiallyBoundVars,
			Algorithm algorithm, List<FilterConstraint> deferredFilters) {
		if (!supportsJoinEstimation() && (sketchBasedJoinEstimator == null || !supportsLmdbPlanning())) {
			return PlanningAttempt.rejected("lmdb-sketch", algorithm,
					"ROBUST_NOT_READY", null,
					List.of("rejected: sketch estimator not ready"));
		}
		if (shouldTryBoundedGreedyFirst(args, algorithm, deferredFilters)) {
			PlanningAttempt boundedGreedyAttempt = toLmdbPlanningAttempt(sketchBasedJoinEstimator
					.planJoinOrderAttempt(args, initiallyBoundVars, Algorithm.GREEDY, this, deferredFilters));
			String boundedGreedyComparisonReason = boundedGreedyComparisonReason(args, deferredFilters);
			boolean compareWithFullPlanner = boundedGreedyComparisonReason != null;
			if (isBoundedGreedyPlan(boundedGreedyAttempt)) {
				if (!compareWithFullPlanner) {
					return withDecisionTrace(boundedGreedyAttempt, boundedGreedySelectedTrace(boundedGreedyAttempt));
				}
				boolean mustCompareWithFullPlanner = mustCompareWithFullPlanner(args, boundedGreedyComparisonReason);
				if (!mustCompareWithFullPlanner && isBelowPlanningCostBoundedGreedyPlan(boundedGreedyAttempt)) {
					return withDecisionTrace(boundedGreedyAttempt,
							belowPlanningCostBoundedGreedySelectedTrace(boundedGreedyAttempt,
									boundedGreedyComparisonReason));
				}
				if (!mustCompareWithFullPlanner && isFiniteDirectLookupBoundedGreedyPlan(boundedGreedyAttempt)) {
					return withDecisionTrace(boundedGreedyAttempt,
							finiteDirectLookupBoundedGreedySelectedTrace(boundedGreedyAttempt,
									boundedGreedyComparisonReason));
				}
			}
			PlanningAttempt selectedAttempt = toLmdbPlanningAttempt(sketchBasedJoinEstimator
					.planJoinOrderAttempt(args, initiallyBoundVars, algorithm, this, deferredFilters));
			if (isBoundedGreedyPlan(boundedGreedyAttempt) && compareWithFullPlanner
					&& selectedAttempt.getPlan().isPresent()) {
				return withDecisionTrace(selectedAttempt,
						boundedGreedyComparedTrace(boundedGreedyAttempt, selectedAttempt,
								boundedGreedyComparisonReason));
			}
			if (selectedAttempt.getPlan().isEmpty() && isBoundedGreedyPlan(boundedGreedyAttempt)) {
				return withDecisionTrace(boundedGreedyAttempt,
						boundedGreedyFallbackTrace(boundedGreedyAttempt, selectedAttempt));
			}
			return withDecisionTrace(selectedAttempt,
					boundedGreedyRejectedTrace(boundedGreedyAttempt, selectedAttempt));
		}
		PlanningAttempt attempt = sketchBasedJoinEstimator.planJoinOrderAttempt(args, initiallyBoundVars, algorithm,
				this, deferredFilters);
		PlanningAttempt selectedAttempt = toLmdbPlanningAttempt(attempt);
		return withDecisionTrace(selectedAttempt, selectedPlannerTrace(selectedAttempt));
	}

	private boolean shouldTryBoundedGreedyFirst(List<TupleExpr> args, Algorithm algorithm,
			List<FilterConstraint> deferredFilters) {
		if (algorithm != Algorithm.DYNAMIC_PROGRAMMING || args == null || args.isEmpty()) {
			return false;
		}
		int filterCount = deferredFilters == null ? 0 : deferredFilters.size();
		return args.size() + filterCount >= BOUNDED_GREEDY_MIN_ACTIONS;
	}

	private String boundedGreedyComparisonReason(List<TupleExpr> args, List<FilterConstraint> deferredFilters) {
		if (deferredFilters != null && !deferredFilters.isEmpty()) {
			return BOUNDED_GREEDY_REASON_DEFERRED_FILTERS;
		}
		if (hasFiniteAssignmentFactor(args)) {
			return BOUNDED_GREEDY_REASON_FINITE_ASSIGNMENTS;
		}
		return null;
	}

	private boolean mustCompareWithFullPlanner(List<TupleExpr> args, String comparisonReason) {
		return BOUNDED_GREEDY_REASON_FINITE_ASSIGNMENTS.equals(comparisonReason)
				&& hasCorrelatedFiniteAssignmentFactor(args);
	}

	private boolean hasFiniteAssignmentFactor(List<TupleExpr> args) {
		if (args == null) {
			return false;
		}
		for (TupleExpr arg : args) {
			if (arg instanceof BindingSetAssignment assignment
					&& assignment.getBindingSets() != null
					&& assignment.getBindingSets().iterator().hasNext()) {
				return true;
			}
		}
		return false;
	}

	private boolean hasCorrelatedFiniteAssignmentFactor(List<TupleExpr> args) {
		if (args == null) {
			return false;
		}
		for (TupleExpr arg : args) {
			if (arg instanceof BindingSetAssignment assignment
					&& assignment.getBindingSets() != null
					&& assignment.getBindingSets().iterator().hasNext()
					&& assignment.getBindingNames().size() > 1) {
				return true;
			}
		}
		return false;
	}

	private boolean isBoundedGreedyPlan(PlanningAttempt attempt) {
		if (attempt.getAlgorithm() != Algorithm.GREEDY || attempt.getPlan().isEmpty()) {
			return false;
		}
		JoinOrderPlan plan = attempt.getPlan().get();
		return isSmallBoundedGreedyPlan(plan) || isFiniteDirectLookupGreedyPlan(plan);
	}

	private boolean isBelowPlanningCostBoundedGreedyPlan(PlanningAttempt attempt) {
		if (attempt.getPlan().isEmpty()) {
			return false;
		}
		double estimatedWorkRows = attempt.getPlan().get().getEstimatedTotalWork();
		return isFiniteNonNegative(estimatedWorkRows)
				&& estimatedWorkRows <= BOUNDED_GREEDY_PLANNING_COST_WORK_ROWS;
	}

	private boolean isFiniteDirectLookupBoundedGreedyPlan(PlanningAttempt attempt) {
		return attempt.getPlan()
				.map(this::isFiniteDirectLookupGreedyPlan)
				.orElse(false);
	}

	private PlanningAttempt withDecisionTrace(PlanningAttempt attempt, String decisionTrace) {
		if (attempt.getPlan().isEmpty() || decisionTrace == null || decisionTrace.isEmpty()) {
			return attempt;
		}
		JoinOrderPlan plan = attempt.getPlan().get();
		Map<String, String> summaryStringMetrics = new HashMap<>(plan.getSummaryStringMetrics());
		summaryStringMetrics.merge(TelemetryMetricNames.OPTIMIZER_DECISION_TRACE, decisionTrace,
				(previous, ignored) -> previous + "; " + decisionTrace);
		JoinOrderPlan tracedPlan = new JoinOrderPlan(plan.getOrderedArgs(), plan.getEstimatedFinalRows(),
				plan.getEstimatedTotalWork(), plan.getDiagnostics(), summaryStringMetrics,
				plan.getSummaryDoubleMetrics(), plan.getSteps());
		return PlanningAttempt.planned(tracedPlan, attempt.getPlannerId(), attempt.getAlgorithm(),
				attempt.getPlannerPath(), attempt.getDiagnostics());
	}

	private String boundedGreedySelectedTrace(PlanningAttempt boundedGreedyAttempt) {
		return "bounded-greedy selected (" + attemptEstimateSummary(boundedGreedyAttempt) + ")";
	}

	private String belowPlanningCostBoundedGreedySelectedTrace(PlanningAttempt boundedGreedyAttempt,
			String comparisonReason) {
		return "boundedGreedyAcceptedReason=belowPlanningCost, boundedGreedyComparisonReason=" + comparisonReason
				+ ", bounded-greedy selected (" + attemptEstimateSummary(boundedGreedyAttempt) + ")";
	}

	private String finiteDirectLookupBoundedGreedySelectedTrace(PlanningAttempt boundedGreedyAttempt,
			String comparisonReason) {
		return "boundedGreedyAcceptedReason=finiteDirectLookup, boundedGreedyComparisonReason=" + comparisonReason
				+ ", bounded-greedy selected (" + attemptEstimateSummary(boundedGreedyAttempt) + ")";
	}

	private String boundedGreedyRejectedTrace(PlanningAttempt boundedGreedyAttempt, PlanningAttempt selectedAttempt) {
		return "bounded-greedy rejected (" + attemptEstimateSummary(boundedGreedyAttempt) + "); "
				+ selectedPlannerLabel(selectedAttempt) + " selected (" + attemptEstimateSummary(selectedAttempt)
				+ ")";
	}

	private String boundedGreedyComparedTrace(PlanningAttempt boundedGreedyAttempt, PlanningAttempt selectedAttempt,
			String rejectedReason) {
		return "boundedGreedyCompared=true, boundedGreedyRejectedReason=" + rejectedReason
				+ ", bounded-greedy rejected (" + attemptEstimateSummary(boundedGreedyAttempt) + "); "
				+ selectedPlannerLabel(selectedAttempt) + " selected (" + attemptEstimateSummary(selectedAttempt)
				+ ")";
	}

	private String boundedGreedyFallbackTrace(PlanningAttempt boundedGreedyAttempt, PlanningAttempt selectedAttempt) {
		return "boundedGreedyCompared=true, boundedGreedyRejectedReason=fullPlannerNoPlan, bounded-greedy selected ("
				+ attemptEstimateSummary(boundedGreedyAttempt) + "); " + selectedPlannerLabel(selectedAttempt)
				+ " rejected (" + attemptEstimateSummary(selectedAttempt) + ")";
	}

	private String selectedPlannerTrace(PlanningAttempt selectedAttempt) {
		return selectedPlannerLabel(selectedAttempt) + " selected (" + attemptEstimateSummary(selectedAttempt) + ")";
	}

	private String selectedPlannerLabel(PlanningAttempt attempt) {
		if (attempt.getAlgorithm() == Algorithm.DYNAMIC_PROGRAMMING) {
			return "pareto-memo";
		}
		if (attempt.getAlgorithm() == Algorithm.GREEDY) {
			return "pareto-beam";
		}
		return String.valueOf(attempt.getAlgorithm()).toLowerCase();
	}

	private String attemptEstimateSummary(PlanningAttempt attempt) {
		if (attempt.getPlan().isEmpty()) {
			return "path=" + attempt.getPlannerPath() + ", no-plan";
		}
		JoinOrderPlan plan = attempt.getPlan().get();
		return "workRows=" + plan.getEstimatedTotalWork() + ", finalRows=" + plan.getEstimatedFinalRows()
				+ ", path=" + attempt.getPlannerPath();
	}

	private boolean isSmallBoundedGreedyPlan(JoinOrderPlan plan) {
		return isFiniteNonNegative(plan.getEstimatedTotalWork())
				&& plan.getEstimatedTotalWork() <= BOUNDED_GREEDY_MAX_WORK_ROWS
				&& isFiniteNonNegative(plan.getEstimatedFinalRows())
				&& plan.getEstimatedFinalRows() <= BOUNDED_GREEDY_MAX_FINAL_ROWS
				&& boundedUncertaintyRows(plan, BOUNDED_GREEDY_MAX_WORK_ROWS);
	}

	private boolean isFiniteDirectLookupGreedyPlan(JoinOrderPlan plan) {
		if (!isFiniteNonNegative(plan.getEstimatedTotalWork())
				|| plan.getEstimatedTotalWork() > BOUNDED_GREEDY_MAX_DIRECT_LOOKUP_WORK_ROWS
				|| !isFiniteNonNegative(plan.getEstimatedFinalRows())
				|| plan.getEstimatedFinalRows() > BOUNDED_GREEDY_MAX_DIRECT_LOOKUP_ROWS
				|| !boundedUncertaintyRows(plan, BOUNDED_GREEDY_MAX_DIRECT_LOOKUP_WORK_ROWS)
				|| plan.getSteps().size() != plan.getOrderedArgs().size()) {
			return false;
		}
		int directLookupSteps = 0;
		double maxPrefixRows = 0.0d;
		for (int i = 0; i < plan.getOrderedArgs().size(); i++) {
			JoinOrderPlanner.PlanStep step = plan.getSteps().get(i);
			if (!isFiniteNonNegative(step.getStepWorkRows()) || !isFiniteNonNegative(step.getPrefixOutputRows())) {
				return false;
			}
			maxPrefixRows = Math.max(maxPrefixRows, step.getPrefixOutputRows());
			if (LmdbJoinPlanSupport.collectPatternIdentities(plan.getOrderedArgs().get(i)).isEmpty()) {
				continue;
			}
			String accessMode = step.getStringMetrics().get(TelemetryMetricNames.PLANNED_INDEX_ACCESS_MODE);
			if (!"directLookup".equals(accessMode)) {
				return false;
			}
			directLookupSteps++;
		}
		return directLookupSteps >= BOUNDED_GREEDY_MIN_DIRECT_LOOKUP_STEPS
				&& maxPrefixRows <= BOUNDED_GREEDY_MAX_DIRECT_LOOKUP_ROWS;
	}

	private boolean boundedUncertaintyRows(JoinOrderPlan plan, double maxUncertaintyRows) {
		double uncertaintyRows = plan.getSummaryDoubleMetrics()
				.getOrDefault(TelemetryMetricNames.PLANNED_UNCERTAINTY_ROWS, 0.0d);
		return Double.isFinite(uncertaintyRows)
				&& uncertaintyRows <= maxUncertaintyRows;
	}

	private PlanningAttempt toLmdbPlanningAttempt(PlanningAttempt attempt) {
		if (attempt.getPlan().isEmpty()) {
			return PlanningAttempt.rejected("lmdb-sketch", attempt.getAlgorithm(), attempt.getPlannerPath(),
					attempt.getRejectedFactor(), attempt.getDiagnostics());
		}
		JoinOrderPlan enrichedPlan = enrichPlanWithAccessMetrics(attempt.getPlan().get());
		return PlanningAttempt.planned(enrichedPlan, "lmdb-sketch", attempt.getAlgorithm(), attempt.getPlannerPath(),
				enrichedPlan.getDiagnostics());
	}

	@Override
	public Optional<JoinOrderPlan> estimateJoinOrder(List<TupleExpr> orderedArgs, Set<String> initiallyBoundVars,
			Algorithm algorithm, List<FilterConstraint> deferredFilters) {
		if (!supportsJoinEstimation()) {
			return Optional.empty();
		}
		Optional<JoinOrderPlan> plan = sketchBasedJoinEstimator.estimateJoinOrder(orderedArgs, initiallyBoundVars,
				algorithm, this, deferredFilters);
		if (plan.isEmpty()) {
			return Optional.empty();
		}
		return Optional.of(enrichPlanWithAccessMetrics(plan.get()));
	}

	private JoinOrderPlan enrichPlanWithAccessMetrics(JoinOrderPlan plan) {
		if (tripleStore == null) {
			return plan;
		}
		if (plan.getSteps().size() != plan.getOrderedArgs().size()) {
			return plan;
		}

		List<JoinOrderPlanner.PlanStep> originalSteps = plan.getSteps();
		List<JoinOrderPlanner.PlanStep> enrichedSteps = null;
		Map<String, Set<Value>> finiteBindingValues = new HashMap<>();
		List<TupleExpr> prefixFactors = new ArrayList<>(plan.getOrderedArgs().size());
		double prefixRowsBeforeStep = 1.0d;
		for (int i = 0; i < plan.getOrderedArgs().size(); i++) {
			int stepIndex = i;
			TupleExpr tupleExpr = plan.getOrderedArgs().get(i);
			JoinOrderPlanner.PlanStep step = originalSteps.get(i);
			JoinOrderPlanner.PlanStep enrichedStep = step;
			Map<String, Set<Value>> finiteValuesForStep = finiteBindingValuesForStep(finiteBindingValues,
					step.getBoundVarsBefore());
			boolean hasFiniteValuesForStep = hasFiniteBindingValues(finiteValuesForStep);
			boolean needsNestedPrefixCost = isFiniteNonNegative(prefixRowsBeforeStep) && prefixRowsBeforeStep > 1.0d;
			if (!hasAccessMetrics(step) || needsNestedPrefixCost
					|| (hasFiniteValuesForStep && !hasFiniteDerivedSurfaceSource(step))) {
				double tracedPrefixRowsBeforeStep = prefixRowsBeforeStep;
				traceEstimate("plan-step-request", tupleExpr, null,
						() -> "step=" + stepIndex
								+ ", boundBefore="
								+ LmdbJoinPlanSupport.describeBindingNames(step.getBoundVarsBefore())
								+ ", prefixRowsBefore=" + estimateTraceRows(tracedPrefixRowsBeforeStep)
								+ ", factorRows=" + estimateTraceRows(step.getFactorOutputRows())
								+ ", prefixRows=" + estimateTraceRows(step.getPrefixOutputRows())
								+ ", work=" + estimateTraceRows(step.getStepWorkRows())
								+ ", finiteValues=" + LmdbJoinPlanSupport.describeBindingNames(
										finiteValuesForStep.keySet())
								+ ", needsNested=" + needsNestedPrefixCost);
				Optional<FactorCostEstimate> factorCostEstimate = estimateEnrichedFactorCost(tupleExpr, step,
						finiteValuesForStep, hasFiniteValuesForStep, prefixFactors, prefixRowsBeforeStep,
						needsNestedPrefixCost);
				if (factorCostEstimate.isPresent()) {
					Map<String, String> stringMetrics = new HashMap<>(step.getStringMetrics());
					Map<String, Double> doubleMetrics = new HashMap<>(step.getDoubleMetrics());
					FactorCostEstimate refinedEstimate = factorCostEstimate.get();
					stringMetrics.putAll(refinedEstimate.getStringMetrics());
					doubleMetrics.putAll(refinedEstimate.getDoubleMetrics());
					double factorOutputRows = step.getFactorOutputRows();
					double prefixOutputRows = step.getPrefixOutputRows();
					double stepWorkRows = step.getStepWorkRows();
					// The stateful transition planner owns row and work flow. This enrichment pass may add access-path
					// diagnostics, but must not replace the selected PlanState/cardinality result with a scalar
					// factor re-estimate.
					doubleMetrics.put(TelemetryMetricNames.PLANNED_CARDINALITY_ROWS, factorOutputRows);
					doubleMetrics.put(TelemetryMetricNames.PLANNED_COST_FINAL_ROWS, prefixOutputRows);
					doubleMetrics.put(TelemetryMetricNames.PLANNED_WORK_ROWS, stepWorkRows);
					doubleMetrics.put(TelemetryMetricNames.PLANNED_COST_WORK_ROWS, stepWorkRows);
					enrichedStep = new JoinOrderPlanner.PlanStep(step.getBoundVarsBefore(),
							factorOutputRows,
							prefixOutputRows, stepWorkRows, stringMetrics, doubleMetrics,
							step.getAppliedFilterIndexes());
					double tracedFactorOutputRows = factorOutputRows;
					double tracedPrefixOutputRows = prefixOutputRows;
					double tracedStepWorkRows = stepWorkRows;
					traceEstimate("plan-step-refined", tupleExpr, null,
							() -> "step=" + stepIndex
									+ ", factorRows=" + estimateTraceRows(tracedFactorOutputRows)
									+ ", prefixRows=" + estimateTraceRows(tracedPrefixOutputRows)
									+ ", work=" + estimateTraceRows(tracedStepWorkRows)
									+ ", " + estimateTraceEstimate(refinedEstimate));
				} else {
					traceEstimate("plan-step-refined-empty", tupleExpr, null, "step=" + stepIndex);
				}
			}
			enrichedStep = normalizePrefixRows(enrichedStep);
			if (enrichedSteps != null) {
				enrichedSteps.add(enrichedStep);
			} else if (enrichedStep != step) {
				enrichedSteps = new ArrayList<>(originalSteps.size());
				enrichedSteps.addAll(originalSteps.subList(0, i));
				enrichedSteps.add(enrichedStep);
			}
			addFiniteBindingValues(finiteBindingValues, tupleExpr);
			prefixFactors.add(tupleExpr);
			double stepFinalRows = stepFinalRows(enrichedStep);
			if (isFiniteNonNegative(stepFinalRows)) {
				prefixRowsBeforeStep = stepFinalRows;
			}
		}

		Map<String, String> summaryStringMetrics = new HashMap<>(plan.getSummaryStringMetrics());
		summaryStringMetrics.put(TelemetryMetricNames.PLANNER_ID, "lmdb-sketch");
		summaryStringMetrics.put(TelemetryMetricNames.OPTIMIZER_PHYSICAL_REFINEMENT,
				"costModel=lmdb, accessPathSelection=per-step");
		Map<String, Double> summaryDoubleMetrics = new HashMap<>(plan.getSummaryDoubleMetrics());
		double estimatedTotalWork = plan.getEstimatedTotalWork();
		double estimatedFinalRows = plan.getEstimatedFinalRows();
		List<JoinOrderPlanner.PlanStep> finalSteps = enrichedSteps == null ? originalSteps : enrichedSteps;
		if (enrichedSteps != null && !finalSteps.isEmpty()) {
			double finalPrefixRows = stepFinalRows(finalSteps.get(finalSteps.size() - 1));
			if (isFiniteNonNegative(finalPrefixRows)) {
				estimatedFinalRows = finalPrefixRows;
			}
		}
		if (enrichedSteps != null) {
			double stepWorkSum = 0.0d;
			boolean finiteStepWork = true;
			for (JoinOrderPlanner.PlanStep step : finalSteps) {
				double stepWorkRows = step.getStepWorkRows();
				if (!isFiniteNonNegative(stepWorkRows)) {
					finiteStepWork = false;
					break;
				}
				stepWorkSum += stepWorkRows;
			}
			if (finiteStepWork && isFiniteNonNegative(stepWorkSum)) {
				estimatedTotalWork = stepWorkSum;
				summaryDoubleMetrics.put(TelemetryMetricNames.PLANNED_WORK_ROWS, estimatedTotalWork);
			}
		}
		if (isFiniteNonNegative(estimatedFinalRows)) {
			summaryDoubleMetrics.put(TelemetryMetricNames.PLANNED_CARDINALITY_ROWS, estimatedFinalRows);
			summaryDoubleMetrics.put(TelemetryMetricNames.PLANNED_COST_FINAL_ROWS, estimatedFinalRows);
		}
		return new JoinOrderPlan(plan.getOrderedArgs(), estimatedFinalRows, estimatedTotalWork,
				plan.getDiagnostics(), summaryStringMetrics, summaryDoubleMetrics, finalSteps);
	}

	private JoinOrderPlanner.PlanStep normalizePrefixRows(JoinOrderPlanner.PlanStep step) {
		double finalRows = stepFinalRows(step);
		if (!isFiniteNonNegative(finalRows)
				|| Double.compare(finalRows, step.getPrefixOutputRows()) == 0) {
			return step;
		}
		return new JoinOrderPlanner.PlanStep(step.getBoundVarsBefore(), step.getFactorOutputRows(), finalRows,
				step.getStepWorkRows(), step.getStringMetrics(), step.getDoubleMetrics(),
				step.getAppliedFilterIndexes());
	}

	private double stepFinalRows(JoinOrderPlanner.PlanStep step) {
		if (step == null) {
			return Double.NaN;
		}
		Double finalRows = step.getDoubleMetrics().get(TelemetryMetricNames.PLANNED_COST_FINAL_ROWS);
		if (finalRows != null && isFiniteNonNegative(finalRows)) {
			return finalRows;
		}
		return step.getPrefixOutputRows();
	}

	private Optional<FactorCostEstimate> estimateEnrichedFactorCost(TupleExpr tupleExpr, JoinOrderPlanner.PlanStep step,
			Map<String, Set<Value>> finiteValuesForStep, boolean hasFiniteValuesForStep,
			List<TupleExpr> prefixFactors, double prefixRowsBeforeStep, boolean needsNestedPrefixCost) {
		if (needsNestedPrefixCost) {
			if (hasFiniteValuesForStep && !prefixFactors.isEmpty()) {
				return estimateFactorCost(tupleExpr, JoinFactorCostModel.CostContext.forOptimization(
						step.getBoundVarsBefore(),
						prefixRowsBeforeStep, Double.NaN, true, true, finiteValuesForStep, prefixFactors));
			}
			return estimateFactorCost(tupleExpr,
					JoinFactorCostModel.CostContext.forOptimization(step.getBoundVarsBefore(), prefixRowsBeforeStep,
							Double.NaN, true, true, Map.of(), List.of()));
		}
		if (hasFiniteValuesForStep && !prefixFactors.isEmpty()) {
			return estimateFactorCost(tupleExpr, JoinFactorCostModel.CostContext.forOptimization(
					step.getBoundVarsBefore(),
					prefixRowsBeforeStep, Double.NaN, false, true, finiteValuesForStep, prefixFactors));
		}
		return estimateFactorCost(tupleExpr, JoinFactorCostModel.CostContext.forOptimization(step.getBoundVarsBefore(),
				prefixRowsBeforeStep, Double.NaN, false, true, Map.of(), List.of()));
	}

	private boolean hasAccessMetrics(JoinOrderPlanner.PlanStep step) {
		return step.getStringMetrics().containsKey(TelemetryMetricNames.PLANNED_INDEX_ACCESS_MODE)
				|| step.getDoubleMetrics().containsKey(TelemetryMetricNames.PLANNED_ACCESS_ROWS);
	}

	private boolean hasFiniteDerivedSurfaceSource(JoinOrderPlanner.PlanStep step) {
		return "lmdb-finite-derived-surface".equals(step.getStringMetrics()
				.get(TelemetryMetricNames.PLANNED_ESTIMATE_SOURCE));
	}

	private boolean hasRowPreservingSubplanSource(FactorCostEstimate estimate) {
		return estimate != null && ROW_PRESERVING_SUBPLAN_SOURCE.equals(estimate.getStringMetrics()
				.get(TelemetryMetricNames.PLANNED_ESTIMATE_SOURCE));
	}

	private boolean hasFiniteDerivedOrConnectedJoinSource(FactorCostEstimate estimate) {
		if (estimate == null) {
			return false;
		}
		String source = estimate.getStringMetrics().get(TelemetryMetricNames.PLANNED_ESTIMATE_SOURCE);
		return "lmdb-finite-derived-surface".equals(source) || "lmdb-connected-join-sample".equals(source);
	}

	@Override
	public Optional<FactorCostEstimate> estimateFactorCost(TupleExpr factor, Set<String> currentlyBoundVars) {
		if (sketchBasedJoinEstimator == null) {
			return estimatePageWalkingFactorCost(factor);
		}
		Optional<FactorCostEstimate> estimate = estimateLmdbFactorCost(factor, currentlyBoundVars);
		if (estimate.isEmpty()) {
			return estimate;
		}
		return fuseOperatorFeedbackEstimate(factor,
				JoinFactorCostModel.CostContext.forOptimization(currentlyBoundVars, Double.NaN, Double.NaN, false,
						true, Map.of(), List.of()),
				estimate.get());
	}

	@Override
	public Optional<JoinFactorCostModel.FilterCostEstimate> estimateFilterCost(
			JoinOrderPlanner.FilterConstraint filter, JoinFactorCostModel.CostContext context) {
		if (filter == null || context == null || !filter.hasNestedTupleExpression() || !filter.isNotExists()) {
			return Optional.empty();
		}
		ValueExpr condition = filter.getCondition()
				.orElse(null);
		TupleExpr antiProbe = antiExistsProbe(condition);
		if (antiProbe == null) {
			return Optional.empty();
		}
		double inputRows = context.getOuterPrefixRows();
		if (!isFiniteNonNegative(inputRows) || inputRows == 0.0d) {
			return Optional.empty();
		}
		Set<String> antiBindings = plannerBindingNames(antiProbe.getBindingNames());
		StatementPattern inputPattern = correlatedAntiExistsPrefixPattern(context.getPrefixFactors(), antiBindings);
		if (inputPattern == null) {
			return Optional.empty();
		}
		Set<String> sharedBindings = plannerBindingNames(inputPattern.getAssuredBindingNames());
		sharedBindings.retainAll(antiBindings);
		CorrelatedAntiExistsExactEstimate exactEstimate = estimateExactCorrelatedAntiExists(inputPattern, antiProbe,
				inputRows, sharedBindings);
		if (exactEstimate == null || !isFiniteNonNegative(exactEstimate.inputRows())
				|| exactEstimate.inputRows() == 0.0d) {
			return Optional.empty();
		}
		double passRatio = Math.clamp(exactEstimate.outputRows() / exactEstimate.inputRows(), 0.0d, 1.0d);
		double outputRows = inputRows * passRatio;
		boolean exactOutputRows = Math.abs(inputRows - exactEstimate.inputRows()) <= 0.5d;
		if (exactOutputRows) {
			outputRows = exactEstimate.outputRows();
		}
		Map<String, String> stringMetrics = Map.of(TelemetryMetricNames.PLANNED_ESTIMATE_SOURCE,
				"lmdb-correlated-anti-exists-filter-exact");
		Map<String, Double> doubleMetrics = new HashMap<>();
		doubleMetrics.put(TelemetryMetricNames.PLANNED_FILTER_PASS_RATIO, passRatio);
		doubleMetrics.put(TelemetryMetricNames.PLANNED_FILTER_CONFIDENCE, exactOutputRows ? 1.0d : 0.85d);
		doubleMetrics.put(TelemetryMetricNames.PLANNED_CARDINALITY_CONFIDENCE, exactOutputRows ? 1.0d : 0.85d);
		doubleMetrics.put(TelemetryMetricNames.PLANNED_WORK_ROWS, exactEstimate.probeWorkRows());
		doubleMetrics.put(TelemetryMetricNames.PLANNED_COST_WORK_ROWS, exactEstimate.probeWorkRows());
		doubleMetrics.put(TelemetryMetricNames.PLANNED_COST_FINAL_ROWS, outputRows);
		doubleMetrics.put(TelemetryMetricNames.PLANNED_CARDINALITY_ROWS, outputRows);
		doubleMetrics.put("plannedAntiExistsProbeWorkRows", exactEstimate.probeWorkRows());
		doubleMetrics.put("plannedAntiExistsProbeOutputRows", exactEstimate.probeOutputRows());
		doubleMetrics.put("plannedAntiExistsMatchedRows", exactEstimate.matchedRows());
		doubleMetrics.put("plannedAntiExistsInputRows", inputRows);
		doubleMetrics.put("plannedAntiExistsExactInputRows", exactEstimate.inputRows());
		doubleMetrics.put("plannedAntiExistsExactProbeRows", exactEstimate.probeOutputRows());
		doubleMetrics.put("plannedAntiExistsExactProbeLookupRows", exactEstimate.probeLookupRows());
		doubleMetrics.put("plannedAntiExistsExactRhsRowsScanned", exactEstimate.rhsRowsScanned());
		doubleMetrics.put("plannedAntiExistsExactWorkRows", exactEstimate.probeWorkRows());
		return Optional.of(new JoinFactorCostModel.FilterCostEstimate(exactEstimate.probeWorkRows(), outputRows,
				passRatio, stringMetrics, doubleMetrics, exactOutputRows));
	}

	@Override
	public Optional<FactorCostEstimate> estimateFactorCost(TupleExpr factor, JoinFactorCostModel.CostContext context) {
		if (sketchBasedJoinEstimator == null) {
			traceEstimate("request-page-walk", factor, context, "reason=no-sketch-estimator");
			return estimatePageWalkingFactorCost(factor);
		}
		if (context == null) {
			traceEstimate("request-null-context", factor, null, "delegating=set-bound-vars");
			return estimateFactorCost(factor, Set.of());
		}
		OptimizationCostScope scope = optimizationCostScope.get();
		ScopedFactorCostCacheKey cacheKey = null;
		if (scope != null) {
			cacheKey = scopedFactorCostCacheKey(factor, context);
			Optional<FactorCostEstimate> cachedEstimate = scope.factorCostCache.get(cacheKey);
			if (cachedEstimate != null) {
				traceEstimate("factor-cost-cache-hit", factor, context,
						() -> cachedEstimate.map(this::estimateTraceEstimate).orElse("empty"));
				return cachedEstimate;
			}
		}
		traceEstimate("request", factor, context, "");
		Optional<FactorCostEstimate> estimate = estimateLmdbFactorCost(factor, context);
		Optional<FactorCostEstimate> baseEstimateTrace = estimate;
		traceEstimate("base", factor, context,
				() -> baseEstimateTrace.map(this::estimateTraceEstimate).orElse("empty"));
		double comparableBaseWorkRows = Double.NaN;
		double comparableBaseOutputRows = Double.NaN;
		if (estimate.isPresent()) {
			if (shouldEstimateFiniteDerivedSurface(factor, context)) {
				OptimizationCounterSnapshot countersBefore = OptimizationCounterSnapshot.capture(
						optimizationCostScope.get());
				comparableBaseWorkRows = comparableBaseWorkRows(factor, context, estimate.get());
				comparableBaseOutputRows = comparableBaseOutputRows(context, estimate.get());
				Optional<FactorCostEstimate> surfaceEstimate = estimateFiniteDerivedJoinSurfaceCost(factor, context,
						estimate.get(), comparableBaseWorkRows, comparableBaseOutputRows, countersBefore);
				if (surfaceEstimate.isPresent()) {
					estimate = surfaceEstimate;
					FactorCostEstimate selectedEstimate = estimate.get();
					traceEstimate("select-finite-derived-surface", factor, context,
							() -> estimateTraceEstimate(selectedEstimate));
				}
			}
		}
		if (estimate.isPresent() && context.getEstimationTier().allowsExactEstimates()) {
			Optional<FactorCostEstimate> connectedEstimate = estimateConnectedJoinFactorCost(factor, context,
					estimate.get(), comparableBaseWorkRows, comparableBaseOutputRows);
			if (connectedEstimate.isPresent()) {
				estimate = connectedEstimate;
				FactorCostEstimate selectedEstimate = estimate.get();
				traceEstimate("select-connected-join", factor, context, () -> estimateTraceEstimate(selectedEstimate));
			}
		}
		if (estimate.isPresent()) {
			Optional<FactorCostEstimate> productEstimate = estimateBoundJoinProductFactorCost(factor, context,
					estimate.get(), comparableBaseWorkRows, comparableBaseOutputRows);
			if (productEstimate.isPresent()) {
				estimate = productEstimate;
				FactorCostEstimate selectedEstimate = estimate.get();
				traceEstimate("select-bound-join-product", factor, context,
						() -> estimateTraceEstimate(selectedEstimate));
			}
		}
		if (estimate.isPresent() && context.getEstimationTier().allowsExactEstimates()) {
			FactorCostEstimate connectedBlend = fuseConnectedPageWalkEstimate(factor, context, estimate.get());
			if (connectedBlend != estimate.get()) {
				estimate = Optional.of(connectedBlend);
				traceEstimate("select-connected-page-walk-blend", factor, context,
						() -> estimateTraceEstimate(connectedBlend));
			}
		}
		if (estimate.isPresent()) {
			estimate = fuseOperatorFeedbackEstimate(factor, context, estimate.get());
			FactorCostEstimate feedbackEstimate = estimate.get();
			traceEstimate("after-feedback", factor, context, () -> estimateTraceEstimate(feedbackEstimate));
		}
		if (estimate.isEmpty() || !context.isNestedIteratorInvocation() || factor instanceof BindingSetAssignment
				|| (estimate.get().isRepeatedInvocationsCosted()
						&& !shouldRevisitRepeatedPhysicalBoundLookup(factor, estimate.get(), context))) {
			Optional<FactorCostEstimate> returnEstimate = estimate;
			traceEstimate("return", factor, context,
					() -> returnEstimate.map(this::estimateTraceEstimate).orElse("empty"));
			return cacheFactorCostEstimate(scope, cacheKey, estimate);
		}
		FactorCostEstimate nestedEstimate = accountNestedInvocationWork(factor, estimate.get(), context);
		traceEstimate("return-nested", factor, context, () -> estimateTraceEstimate(nestedEstimate));
		return cacheFactorCostEstimate(scope, cacheKey, Optional.of(nestedEstimate));
	}

	private boolean shouldRevisitRepeatedPhysicalBoundLookup(TupleExpr factor, FactorCostEstimate estimate,
			JoinFactorCostModel.CostContext context) {
		if (factor == null || estimate == null || context == null) {
			traceEstimate("revisit-repeated-physical-lookup-reject", factor, context, "reason=missing-input");
			return false;
		}
		if (!context.isNestedIteratorInvocation()) {
			traceEstimate("revisit-repeated-physical-lookup-reject", factor, context, "reason=not-nested");
			return false;
		}
		if (!estimate.isRepeatedInvocationsCosted()) {
			traceEstimate("revisit-repeated-physical-lookup-reject", factor, context, "reason=not-repeated");
			return false;
		}
		if (estimate.hasExactOutputRows()) {
			traceEstimate("revisit-repeated-physical-lookup-reject", factor, context, "reason=exact-output");
			return false;
		}
		if (exactStatementLookupAlreadyCostsRepeatedInvocations(estimate, context.getOuterPrefixRows())) {
			traceEstimate("revisit-repeated-physical-lookup-reject", factor, context,
					"reason=exact-statement-repeated-costed");
			return false;
		}
		if (!usesPhysicalBoundLookup(estimate)) {
			traceEstimate("revisit-repeated-physical-lookup-reject", factor, context,
					"reason=not-physical-bound-lookup");
			return false;
		}
		if (!usesOuterBindingsForLookup(factor, estimate, context)) {
			traceEstimate("revisit-repeated-physical-lookup-reject", factor, context,
					"reason=lookup-not-correlated-with-outer");
			return false;
		}
		double distinctLookupBindings = context.getDistinctLookupBindings();
		if (!isFiniteNonNegative(distinctLookupBindings) || distinctLookupBindings <= 0.0d) {
			distinctLookupBindings = lookupDomainDistinctRows(factor, estimate, context);
		}
		double repeatedInvocations = repeatedInvocations(estimate, context.getOuterPrefixRows(),
				distinctLookupBindings);
		if (!isFiniteNonNegative(repeatedInvocations) || repeatedInvocations <= 0.0d) {
			traceEstimate("revisit-repeated-physical-lookup-reject", factor, context,
					"reason=bad-repeated-invocations, repeatedInvocations="
							+ estimateTraceRows(repeatedInvocations));
			return false;
		}
		if (!isFiniteNonNegative(distinctLookupBindings) || distinctLookupBindings <= 0.0d) {
			distinctLookupBindings = repeatedInvocations;
		}
		double lookupDomainOutputRows = lookupDomainAverageRepeatedOutputRows(factor, estimate, context,
				repeatedInvocations, distinctLookupBindings);
		if (!isFiniteNonNegative(lookupDomainOutputRows)) {
			traceEstimate("revisit-repeated-physical-lookup-reject", factor, context,
					"reason=no-lookup-domain-output, repeatedInvocations="
							+ estimateTraceRows(repeatedInvocations)
							+ ", distinctLookup=" + estimateTraceRows(distinctLookupBindings));
			return false;
		}
		double lookupDomainWorkRows = lookupDomainRepeatedWorkRows(lookupDomainOutputRows, repeatedInvocations,
				estimate);
		boolean outputRaisesEstimate = !isFiniteNonNegative(estimate.getOutputRows())
				|| lookupDomainOutputRows > estimate.getOutputRows();
		boolean workRaisesEstimate = isFiniteNonNegative(lookupDomainWorkRows)
				&& (!isFiniteNonNegative(estimate.getWorkRows()) || lookupDomainWorkRows > estimate.getWorkRows());
		if (outputRaisesEstimate || workRaisesEstimate) {
			traceEstimate("revisit-repeated-physical-lookup", factor, context,
					"lookupDomainOutput=" + estimateTraceRows(lookupDomainOutputRows)
							+ ", lookupDomainWork=" + estimateTraceRows(lookupDomainWorkRows)
							+ ", currentOutput=" + estimateTraceRows(estimate.getOutputRows())
							+ ", currentWork=" + estimateTraceRows(estimate.getWorkRows()));
			return true;
		}
		traceEstimate("revisit-repeated-physical-lookup-reject", factor, context,
				"reason=lookup-domain-not-larger, lookupDomainOutput="
						+ estimateTraceRows(lookupDomainOutputRows)
						+ ", lookupDomainWork=" + estimateTraceRows(lookupDomainWorkRows)
						+ ", currentOutput=" + estimateTraceRows(estimate.getOutputRows())
						+ ", currentWork=" + estimateTraceRows(estimate.getWorkRows()));
		return false;
	}

	private boolean shouldEstimateFiniteDerivedSurface(TupleExpr factor, JoinFactorCostModel.CostContext context) {
		if (context == null || !introducesNewBinding(factor, context.getCurrentlyBoundVars())) {
			return false;
		}
		if (context.getEstimationTier().allowsExactEstimates()) {
			return true;
		}
		return hasFiniteBindingValues(context.getFiniteBindingValues())
				&& !context.getPrefixFactors().isEmpty()
				&& context.getPrefixFactors().size() + 1 <= FINITE_DERIVED_SURFACE_MAX_FACTORS;
	}

	private Optional<FactorCostEstimate> cacheFactorCostEstimate(OptimizationCostScope scope,
			ScopedFactorCostCacheKey cacheKey, Optional<FactorCostEstimate> estimate) {
		if (scope != null && cacheKey != null) {
			// Probe keys wrap caller-owned collections; snapshot them before the key outlives this call.
			scope.factorCostCache.put(cacheKey.toStorable(), estimate);
		}
		return estimate;
	}

	private Optional<FactorCostEstimate> fuseOperatorFeedbackEstimate(TupleExpr factor,
			JoinFactorCostModel.CostContext context, FactorCostEstimate baseEstimate) {
		if (operatorFeedbackStats == null || factor == null || baseEstimate == null) {
			return Optional.ofNullable(baseEstimate);
		}
		if (baseEstimate.hasExactOutputRows() || hasProtectedEstimateSource(baseEstimate)) {
			return Optional.of(baseEstimate);
		}
		double baseRows = baseEstimate.getOutputRows();
		double baseWorkRows = baseEstimate.getWorkRows();
		if (!isFiniteNonNegative(baseRows) || !isFiniteNonNegative(baseWorkRows)) {
			return Optional.of(baseEstimate);
		}
		double leftRows = feedbackLeftRows(factor, context);
		double rightRows = feedbackRightRows(factor, context);
		String executionMode = operatorFeedbackExecutionMode(factor, context);
		LmdbOperatorFeedbackStats.OperatorEstimate feedback = operatorFeedbackStats.estimate(factor, leftRows,
				rightRows, baseRows, baseWorkRows, executionMode);
		if (feedback == null) {
			return Optional.of(baseEstimate);
		}
		return Optional.of(fusedFeedbackEstimate(baseEstimate, feedback));
	}

	private boolean hasProtectedEstimateSource(FactorCostEstimate estimate) {
		String source = estimate.getStringMetrics().get(TelemetryMetricNames.PLANNED_ESTIMATE_SOURCE);
		return hasProtectedEstimateSource(source);
	}

	private boolean hasProtectedEstimateSource(String source) {
		return "lmdb-finite-binding-lookup".equals(source)
				|| "lmdb-finite-derived-surface".equals(source)
				|| (source != null && source.startsWith("omni-"));
	}

	private Map<String, Double> parentDoubleMetrics(FactorCostEstimate childEstimate) {
		Map<String, Double> doubleMetrics = childEstimate == null
				? new HashMap<>()
				: new HashMap<>(childEstimate.getDoubleMetrics());
		// This is physical-child state. If copied to a parent operator, LEO may wait for the parent to close
		// once per child lookup and reject a completed operator as incomplete.
		doubleMetrics.remove(PLANNED_OPERATOR_REPEATED_INVOCATIONS);
		return doubleMetrics;
	}

	private FactorCostEstimate fusedFeedbackEstimate(FactorCostEstimate baseEstimate,
			LmdbOperatorFeedbackStats.OperatorEstimate feedback) {
		Map<String, String> stringMetrics = new HashMap<>(baseEstimate.getStringMetrics());
		String baseSource = stringMetrics.get(TelemetryMetricNames.PLANNED_ESTIMATE_SOURCE);
		if (baseSource != null) {
			stringMetrics.put("plannedBaseEstimateSource", baseSource);
		}
		String bridgeJoinVar = stringMetrics.get("plannedBoundJoinProductJoinVar");
		if (bridgeJoinVar != null) {
			stringMetrics.putIfAbsent(PLANNED_BRIDGE_CORRECTION_JOIN_VAR, bridgeJoinVar);
			stringMetrics.putIfAbsent(PLANNED_BRIDGE_CORRECTION_SOURCE, BOUND_JOIN_PRODUCT_SOURCE);
		}
		stringMetrics.put(TelemetryMetricNames.PLANNED_ESTIMATE_SOURCE, feedback.source());
		stringMetrics.put("plannedEstimateFusion", "operator_feedback");
		stringMetrics.put("plannedOperatorFeedbackSource", feedback.source());
		if (feedback.feedbackKey() != null) {
			stringMetrics.put("plannedOperatorFeedbackKey", feedback.feedbackKey());
		}

		Map<String, Double> doubleMetrics = new HashMap<>(baseEstimate.getDoubleMetrics());
		double robustWorkRows = robustFeedbackWorkRows(feedback);
		double physicalWorkFloor = feedbackPhysicalWorkFloor(baseEstimate);
		if (isFiniteNonNegative(physicalWorkFloor)) {
			robustWorkRows = Math.max(robustWorkRows, physicalWorkFloor);
			doubleMetrics.put("plannedOperatorFeedbackPhysicalWorkFloor", physicalWorkFloor);
		}
		doubleMetrics.put(TelemetryMetricNames.PLANNED_WORK_ROWS, robustWorkRows);
		doubleMetrics.put("plannedBaseRows", baseEstimate.getOutputRows());
		doubleMetrics.put("plannedBaseWorkRows", baseEstimate.getWorkRows());
		doubleMetrics.put("plannedOperatorFeedbackRows", feedback.rows());
		doubleMetrics.put("plannedOperatorFeedbackWorkRows", feedback.workRows());
		doubleMetrics.put(PLANNED_OPERATOR_FEEDBACK_ROBUST_WORK_ROWS, robustWorkRows);
		doubleMetrics.put("plannedOperatorFeedbackEvidence", (double) feedback.evidenceCount());
		doubleMetrics.put("plannedOperatorFeedbackConfidence", feedback.confidence());
		doubleMetrics.put(PLANNED_OPERATOR_FEEDBACK_CORRECTION_CONFIDENCE, feedback.correctionConfidence());
		doubleMetrics.put(PLANNED_OPERATOR_FEEDBACK_ROW_Q_ERROR_MEAN, feedback.rowQErrorMean());
		doubleMetrics.put(PLANNED_OPERATOR_FEEDBACK_ROW_Q_ERROR_MAX, feedback.rowQErrorMax());
		doubleMetrics.put(PLANNED_OPERATOR_FEEDBACK_WORK_Q_ERROR_MEAN, feedback.workQErrorMean());
		doubleMetrics.put(PLANNED_OPERATOR_FEEDBACK_WORK_Q_ERROR_MAX, feedback.workQErrorMax());
		doubleMetrics.put(PLANNED_OPERATOR_FEEDBACK_UNCERTAINTY_ROWS, feedback.uncertaintyRows());
		doubleMetrics.put(TelemetryMetricNames.PLANNED_UNCERTAINTY_ROWS, feedback.uncertaintyRows());
		doubleMetrics.put(TelemetryMetricNames.PLANNED_COST_UNCERTAINTY_ROWS, feedback.uncertaintyRows());
		doubleMetrics.put(TelemetryMetricNames.PLANNED_CARDINALITY_CONFIDENCE, feedback.confidence());
		double rowQError = feedback.rowQErrorMax();
		if (isFiniteNonNegative(rowQError) && rowQError > 1.0d && isFiniteNonNegative(feedback.rows())) {
			doubleMetrics.put(TelemetryMetricNames.PLANNED_CARDINALITY_LOWER, feedback.rows() / rowQError);
			doubleMetrics.put(TelemetryMetricNames.PLANNED_CARDINALITY_UPPER, feedback.rows() * rowQError);
		}
		doubleMetrics.put(TelemetryMetricNames.PLANNED_OBJECTIVE_SCORE, robustWorkRows);

		FactorCostEstimate estimate = new FactorCostEstimate(robustWorkRows, feedback.rows(), stringMetrics,
				doubleMetrics,
				baseEstimate.hasPhysicalAccessPath(), baseEstimate.isDirectLookup(),
				baseEstimate.getLookupComponentMask(),
				baseEstimate.getMissingLookupComponentMask(), baseEstimate.getAccessRowsBeforeFilter(), true, false);
		return baseEstimate.getBagEstimate()
				.map(estimate::withBag)
				.orElse(estimate);
	}

	private double feedbackPhysicalWorkFloor(FactorCostEstimate baseEstimate) {
		if (baseEstimate == null || !baseEstimate.hasPhysicalAccessPath() || baseEstimate.isDirectLookup()) {
			return Double.NaN;
		}
		Map<String, Double> doubleMetrics = baseEstimate.getDoubleMetrics();
		double floor = maxFiniteNonNegative(baseEstimate.getWorkRows(), baseEstimate.getAccessRowsBeforeFilter());
		floor = maxFiniteNonNegative(floor,
				doubleMetrics.getOrDefault(TelemetryMetricNames.PLANNED_ACCESS_WORK_ROWS, Double.NaN));
		floor = maxFiniteNonNegative(floor,
				doubleMetrics.getOrDefault(TelemetryMetricNames.PLANNED_ACCESS_ROWS, Double.NaN));
		return isFiniteNonNegative(floor) ? floor : Double.NaN;
	}

	private double maxFiniteNonNegative(double first, double second) {
		boolean hasFirst = isFiniteNonNegative(first);
		boolean hasSecond = isFiniteNonNegative(second);
		if (hasFirst && hasSecond) {
			return Math.max(first, second);
		}
		if (hasFirst) {
			return first;
		}
		return hasSecond ? second : Double.NaN;
	}

	private double robustFeedbackWorkRows(LmdbOperatorFeedbackStats.OperatorEstimate feedback) {
		double workRows = feedback.workRows();
		if (!isFiniteNonNegative(workRows) || workRows == 0.0d) {
			return workRows;
		}
		double qError = Math.max(feedback.rowQErrorMax(), feedback.workQErrorMax());
		if (!isFiniteNonNegative(qError) || qError <= 1.0d) {
			return workRows;
		}
		double confidenceGap = 1.0d - Math.max(0.0d, Math.min(1.0d, feedback.confidence()));
		double penalty = Math.min(0.50d, Math.max(0.0d, qError - 1.0d) * confidenceGap * 0.05d);
		double robustWorkRows = workRows * (1.0d + penalty);
		return isFiniteNonNegative(robustWorkRows) ? robustWorkRows : workRows;
	}

	private double feedbackLeftRows(TupleExpr factor, JoinFactorCostModel.CostContext context) {
		if (!(factor instanceof BinaryTupleOperator binary)) {
			return Double.NaN;
		}
		return feedbackRows(binary.getLeftArg(), context, contextBoundVars(context), contextBoundVarMask(context));
	}

	private double feedbackRightRows(TupleExpr factor, JoinFactorCostModel.CostContext context) {
		if (!(factor instanceof BinaryTupleOperator binary)) {
			return Double.NaN;
		}
		if (factor instanceof Union) {
			return feedbackRows(binary.getRightArg(), context, contextBoundVars(context), contextBoundVarMask(context));
		}
		if (context != null && context.hasCurrentlyBoundVarMask()) {
			long rightBoundMask = contextBoundVarMask(context) | bindingMask(context.getVariableNames(),
					binary.getLeftArg().getBindingNames());
			return feedbackRows(binary.getRightArg(), context, null, rightBoundMask);
		}
		Set<String> rightBoundVars = unionBindingNames(contextBoundVars(context),
				binary.getLeftArg().getBindingNames());
		return feedbackRows(binary.getRightArg(), context, rightBoundVars, 0L);
	}

	private double feedbackRows(TupleExpr tupleExpr, JoinFactorCostModel.CostContext context, Set<String> boundVars,
			long boundVarMask) {
		if (tupleExpr == null) {
			return Double.NaN;
		}
		if (context != null && context.hasCurrentlyBoundVarMask()) {
			return estimateFactorOutputRows(tupleExpr, context.getVariableNames(), boundVarMask);
		}
		return estimateFactorOutputRows(tupleExpr, boundVars == null ? Set.of() : boundVars);
	}

	private Set<String> contextBoundVars(JoinFactorCostModel.CostContext context) {
		return context == null ? Set.of() : context.getCurrentlyBoundVars();
	}

	private long contextBoundVarMask(JoinFactorCostModel.CostContext context) {
		return context == null || !context.hasCurrentlyBoundVarMask() ? 0L : context.getCurrentlyBoundVarMask();
	}

	private long bindingMask(String[] variableNames, Set<String> bindingNames) {
		if (variableNames == null || variableNames.length == 0 || bindingNames == null || bindingNames.isEmpty()) {
			return 0L;
		}
		long mask = 0L;
		for (int i = 0; i < variableNames.length && i < Long.SIZE; i++) {
			if (bindingNames.contains(variableNames[i])) {
				mask |= 1L << i;
			}
		}
		return mask;
	}

	private Optional<FactorCostEstimate> estimatePageWalkingFactorCost(TupleExpr factor) {
		if (factor == null) {
			return Optional.empty();
		}
		double outputRows = estimateFactorOutputRows(factor, Set.of());
		return isFiniteNonNegative(outputRows) ? Optional.of(new FactorCostEstimate(outputRows, outputRows))
				: Optional.empty();
	}

	private boolean introducesNewBinding(TupleExpr factor, Set<String> currentlyBoundVars) {
		if (factor == null) {
			return false;
		}
		Set<String> boundVars = currentlyBoundVars == null ? Set.of() : currentlyBoundVars;
		for (String bindingName : factor.getBindingNames()) {
			if (bindingName != null && !bindingName.startsWith("_const_") && !boundVars.contains(bindingName)) {
				return true;
			}
		}
		return false;
	}

	private Optional<FactorCostEstimate> estimateLmdbFactorCost(TupleExpr factor,
			JoinFactorCostModel.CostContext context) {
		Optional<FactorCostEstimate> finiteFilterEstimate = estimateBindingSetAssignmentFactorCost(factor, context);
		if (finiteFilterEstimate.isPresent()) {
			return finiteFilterEstimate;
		}
		if (factor instanceof Join join) {
			Optional<FactorCostEstimate> joinEstimate = estimateInnerJoinBoundLookupFactorCost(join, context);
			if (joinEstimate.isPresent()) {
				return joinEstimate;
			}
		}
		if (factor instanceof LeftJoin leftJoin) {
			Optional<FactorCostEstimate> optionalEstimate = estimateOptionalBoundLookupFactorCost(leftJoin,
					context);
			if (optionalEstimate.isPresent()) {
				return optionalEstimate;
			}
		}
		if (factor instanceof Difference difference) {
			Optional<FactorCostEstimate> minusEstimate = estimateMinusBoundProbeFactorCost(difference, context);
			if (minusEstimate.isPresent()) {
				return minusEstimate;
			}
		}
		RequestedAccessPath requestedAccessPath = RequestedAccessPath.of(context);
		Optional<FactorCostEstimate> prefixPathEstimate = estimatePropertyPathFactorCost(factor,
				context.getCurrentlyBoundVars(), context.getPrefixFactors(), context.shouldCollectMetrics());
		if (prefixPathEstimate.isPresent()) {
			return prefixPathEstimate;
		}
		if (context.hasCurrentlyBoundVarMask()) {
			return estimateLmdbFactorCost(factor, context.getVariableNames(),
					context.getCurrentlyBoundVarMask(),
					Double.NaN, context.shouldCollectMetrics(), context.getFiniteBindingValues(),
					context.getEstimationTier(), requestedAccessPath);
		}
		return estimateLmdbFactorCost(factor, context.getCurrentlyBoundVars(), Double.NaN,
				context.shouldCollectMetrics(), context.getFiniteBindingValues(), context.getEstimationTier(),
				requestedAccessPath);
	}

	private Optional<FactorCostEstimate> estimateInnerJoinBoundLookupFactorCost(Join join,
			JoinFactorCostModel.CostContext context) {
		if (join == null || context == null || context.hasRequestedAccessPath()
				|| TupleExprs.isVariableScopeChange(join)
				|| TupleExprs.isVariableScopeChange(join.getRightArg())
				|| TupleExprs.containsSubquery(join.getRightArg())
				|| "hash".equals(join.getStringMetricPlanned("optimizer.joinAlgorithmHint"))) {
			return Optional.empty();
		}
		TupleExpr leftArg = join.getLeftArg();
		TupleExpr rightArg = join.getRightArg();
		Set<String> leftAssuredBindings = plannerBindingNames(leftArg.getAssuredBindingNames());
		Set<String> rightBindings = plannerBindingNames(rightArg.getBindingNames());
		Set<String> sharedBindings = new HashSet<>(leftAssuredBindings);
		sharedBindings.retainAll(rightBindings);
		if (sharedBindings.isEmpty()) {
			return Optional.empty();
		}

		Optional<FactorCostEstimate> leftEstimate = estimateFactorCost(leftArg, context);
		if (leftEstimate.isEmpty()) {
			return Optional.empty();
		}
		FactorCostEstimate left = leftEstimate.get();
		double leftRows = left.getOutputRows();
		if (!isPositiveFinite(leftRows)) {
			return Optional.empty();
		}
		JoinFactorCostModel.CostContext rightContext = optionalRightCostContext(context, leftArg, rightArg, leftRows,
				sharedBindings);
		Optional<FactorCostEstimate> rightEstimate = estimateFactorCost(rightArg, rightContext);
		if (rightEstimate.isEmpty()) {
			return Optional.empty();
		}
		FactorCostEstimate right = rightEstimate.get();
		double rightRows = right.getOutputRows();
		double rightWorkRows = right.getWorkRows();
		if (!isFiniteNonNegative(rightRows) || !isFiniteNonNegative(rightWorkRows)) {
			return Optional.empty();
		}
		double leftWorkRows = left.getWorkRows();
		if (!isFiniteNonNegative(leftWorkRows)) {
			leftWorkRows = leftRows;
		}
		double outputRows = estimateFactorOutputRows(join, context.getCurrentlyBoundVars());
		if (!isFiniteNonNegative(outputRows)) {
			outputRows = Math.max(1.0d, Math.min(leftRows, rightRows));
		}
		double workRows = leftWorkRows + Math.max(rightWorkRows, rightRows);
		if (!isFiniteNonNegative(workRows)) {
			return Optional.empty();
		}
		workRows = Math.max(workRows, outputRows);

		Map<String, String> stringMetrics = new HashMap<>(right.getStringMetrics());
		String rightSource = stringMetrics.get(TelemetryMetricNames.PLANNED_ESTIMATE_SOURCE);
		if (rightSource != null) {
			stringMetrics.put("plannedInnerJoinRightBaseEstimateSource", rightSource);
		}
		String leftSource = left.getStringMetrics()
				.get(TelemetryMetricNames.PLANNED_ESTIMATE_SOURCE);
		if (leftSource != null) {
			stringMetrics.put("plannedInnerJoinLeftBaseEstimateSource", leftSource);
		}
		stringMetrics.put(TelemetryMetricNames.PLANNED_ESTIMATE_SOURCE, INNER_JOIN_BOUND_LOOKUP_SOURCE);
		stringMetrics.put("plannedInnerJoinSharedBindings", new TreeSet<>(sharedBindings).toString());

		Map<String, Double> doubleMetrics = parentDoubleMetrics(right);
		doubleMetrics.put("plannedInnerJoinLeftRows", leftRows);
		doubleMetrics.put("plannedInnerJoinLeftWorkRows", leftWorkRows);
		doubleMetrics.put("plannedInnerJoinRightRows", rightRows);
		doubleMetrics.put("plannedInnerJoinRightWorkRows", rightWorkRows);
		doubleMetrics.put("plannedInnerJoinOutputRows", outputRows);
		propagateMaterializedFilterWorkRowsPerInvocation(doubleMetrics, left, right);
		doubleMetrics.put(TelemetryMetricNames.PLANNED_CARDINALITY_ROWS, outputRows);
		doubleMetrics.put(TelemetryMetricNames.PLANNED_WORK_ROWS, workRows);
		doubleMetrics.put(TelemetryMetricNames.PLANNED_COST_FINAL_ROWS, outputRows);
		doubleMetrics.put(TelemetryMetricNames.PLANNED_COST_WORK_ROWS, workRows);
		doubleMetrics.put(TelemetryMetricNames.PLANNED_OBJECTIVE_SCORE, workRows);

		return Optional.of(new FactorCostEstimate(workRows, outputRows, stringMetrics, doubleMetrics, false,
				false, 0, 0, Double.NaN, true, false));
	}

	private Optional<FactorCostEstimate> estimateOptionalBoundLookupFactorCost(LeftJoin leftJoin,
			JoinFactorCostModel.CostContext context) {
		if (leftJoin == null || context == null || context.hasRequestedAccessPath()
				|| TupleExprs.isVariableScopeChange(leftJoin) || leftJoin.getCondition() != null) {
			return Optional.empty();
		}
		TupleExpr leftArg = leftJoin.getLeftArg();
		TupleExpr rightArg = leftJoin.getRightArg();
		Set<String> leftAssuredBindings = plannerBindingNames(leftArg.getAssuredBindingNames());
		Set<String> rightBindings = plannerBindingNames(rightArg.getBindingNames());
		Set<String> sharedBindings = new HashSet<>(leftAssuredBindings);
		sharedBindings.retainAll(rightBindings);
		if (sharedBindings.isEmpty()) {
			return Optional.empty();
		}

		Optional<FactorCostEstimate> leftEstimate = estimateFactorCost(leftArg, context);
		if (leftEstimate.isEmpty()) {
			return Optional.empty();
		}
		double leftRows = leftEstimate.get()
				.getOutputRows();
		if (!isPositiveFinite(leftRows)) {
			return Optional.empty();
		}
		JoinFactorCostModel.CostContext rightContext = optionalRightCostContext(context, leftArg, rightArg, leftRows,
				sharedBindings);
		Optional<FactorCostEstimate> rightEstimate = estimateFactorCost(rightArg, rightContext);
		if (rightEstimate.isEmpty()) {
			return Optional.empty();
		}
		FactorCostEstimate left = leftEstimate.get();
		FactorCostEstimate right = rightEstimate.get();
		double rightRows = right.getOutputRows();
		double rightWorkRows = right.getWorkRows();
		if (!isFiniteNonNegative(rightRows) || !isFiniteNonNegative(rightWorkRows)) {
			return Optional.empty();
		}
		double leftWorkRows = left.getWorkRows();
		if (!isFiniteNonNegative(leftWorkRows)) {
			leftWorkRows = leftRows;
		}
		double outputRows = Math.max(leftRows, rightRows);
		double optionalBridgeRows = optionalBridgeProductRows(leftJoin, leftRows);
		if (isFiniteNonNegative(optionalBridgeRows)) {
			outputRows = Math.max(outputRows, optionalBridgeRows);
		}
		double workRows = leftWorkRows + Math.max(rightWorkRows, rightRows);
		if (!isFiniteNonNegative(workRows)) {
			return Optional.empty();
		}
		workRows = Math.max(workRows, outputRows);

		Map<String, String> stringMetrics = new HashMap<>(right.getStringMetrics());
		String rightSource = stringMetrics.get(TelemetryMetricNames.PLANNED_ESTIMATE_SOURCE);
		if (rightSource != null) {
			stringMetrics.put("plannedOptionalRightBaseEstimateSource", rightSource);
		}
		String leftSource = left.getStringMetrics()
				.get(TelemetryMetricNames.PLANNED_ESTIMATE_SOURCE);
		if (leftSource != null) {
			stringMetrics.put("plannedOptionalLeftBaseEstimateSource", leftSource);
		}
		stringMetrics.put(TelemetryMetricNames.PLANNED_ESTIMATE_SOURCE, OPTIONAL_BOUND_LOOKUP_SOURCE);
		stringMetrics.put("plannedOptionalSharedBindings", new TreeSet<>(sharedBindings).toString());

		Map<String, Double> doubleMetrics = parentDoubleMetrics(right);
		doubleMetrics.put("plannedOptionalLeftRows", leftRows);
		doubleMetrics.put("plannedOptionalLeftWorkRows", leftWorkRows);
		doubleMetrics.put("plannedOptionalRightRows", rightRows);
		doubleMetrics.put("plannedOptionalRightWorkRows", rightWorkRows);
		if (isFiniteNonNegative(optionalBridgeRows)) {
			doubleMetrics.put("plannedOptionalBridgeProductRows", optionalBridgeRows);
		}
		doubleMetrics.put("plannedOptionalOutputRows", outputRows);
		propagateMaterializedFilterWorkRowsPerInvocation(doubleMetrics, left, right);
		doubleMetrics.put(TelemetryMetricNames.PLANNED_CARDINALITY_ROWS, outputRows);
		doubleMetrics.put(TelemetryMetricNames.PLANNED_WORK_ROWS, workRows);
		doubleMetrics.put(TelemetryMetricNames.PLANNED_COST_FINAL_ROWS, outputRows);
		doubleMetrics.put(TelemetryMetricNames.PLANNED_COST_WORK_ROWS, workRows);
		doubleMetrics.put(TelemetryMetricNames.PLANNED_OBJECTIVE_SCORE, workRows);

		return Optional.of(new FactorCostEstimate(workRows, outputRows, stringMetrics, doubleMetrics, false,
				false, 0, 0, Double.NaN, true, false));
	}

	private Optional<FactorCostEstimate> estimateMinusBoundProbeFactorCost(Difference difference,
			JoinFactorCostModel.CostContext context) {
		if (difference == null || context == null || context.hasRequestedAccessPath()
				|| TupleExprs.isVariableScopeChange(difference)) {
			return Optional.empty();
		}
		TupleExpr leftArg = difference.getLeftArg();
		TupleExpr rightArg = difference.getRightArg();
		if (leftArg == null || rightArg == null || TupleExprs.isVariableScopeChange(rightArg)) {
			return Optional.empty();
		}
		Set<String> leftAssuredBindings = plannerBindingNames(leftArg.getAssuredBindingNames());
		Set<String> rightBindings = plannerBindingNames(rightArg.getBindingNames());
		Set<String> sharedBindings = new HashSet<>(leftAssuredBindings);
		sharedBindings.retainAll(rightBindings);
		if (sharedBindings.isEmpty()) {
			return Optional.empty();
		}

		Optional<FactorCostEstimate> leftEstimate = estimateFactorCost(leftArg, context);
		if (leftEstimate.isEmpty()) {
			return Optional.empty();
		}
		FactorCostEstimate left = leftEstimate.get();
		double leftRows = left.getOutputRows();
		if (!isPositiveFinite(leftRows)) {
			return Optional.empty();
		}
		Optional<OmniCorrelatedProbeEstimate> omniAntiEstimate = sketchBasedJoinEstimator == null
				? Optional.empty()
				: sketchBasedJoinEstimator.estimateOmniCorrelatedAntiProbe(leftArg, rightArg, sharedBindings,
						leftRows);
		if (omniAntiEstimate.isPresent()) {
			return Optional.of(omniMinusAntiJoinFactorCost(left, omniAntiEstimate.get(), sharedBindings));
		}
		JoinFactorCostModel.CostContext rightContext = optionalRightCostContext(context, leftArg, rightArg, leftRows,
				sharedBindings);
		Optional<FactorCostEstimate> rightEstimate = estimateFactorCost(rightArg, rightContext);
		if (rightEstimate.isEmpty()) {
			return Optional.empty();
		}
		FactorCostEstimate right = rightEstimate.get();
		double rightRows = right.getOutputRows();
		double rightWorkRows = right.getWorkRows();
		if (!isFiniteNonNegative(rightRows) || !isFiniteNonNegative(rightWorkRows)) {
			return Optional.empty();
		}
		double leftWorkRows = left.getWorkRows();
		if (!isFiniteNonNegative(leftWorkRows)) {
			leftWorkRows = leftRows;
		}
		double outputRows = leftRows;
		double estimatedOutputRows = estimateFactorOutputRows(difference, context.getCurrentlyBoundVars());
		if (isFiniteNonNegative(estimatedOutputRows)) {
			outputRows = Math.min(leftRows, estimatedOutputRows);
		}
		double workRows = leftWorkRows + Math.max(rightWorkRows, rightRows);
		if (!isFiniteNonNegative(workRows)) {
			return Optional.empty();
		}
		workRows = Math.max(workRows, outputRows);

		Map<String, String> stringMetrics = new HashMap<>(right.getStringMetrics());
		String rightSource = stringMetrics.get(TelemetryMetricNames.PLANNED_ESTIMATE_SOURCE);
		if (rightSource != null) {
			stringMetrics.put("plannedMinusRightBaseEstimateSource", rightSource);
		}
		String leftSource = left.getStringMetrics()
				.get(TelemetryMetricNames.PLANNED_ESTIMATE_SOURCE);
		if (leftSource != null) {
			stringMetrics.put("plannedMinusLeftBaseEstimateSource", leftSource);
		}
		stringMetrics.put(TelemetryMetricNames.PLANNED_ESTIMATE_SOURCE, MINUS_BOUND_PROBE_SOURCE);
		stringMetrics.put("plannedMinusSharedBindings", new TreeSet<>(sharedBindings).toString());

		Map<String, Double> doubleMetrics = parentDoubleMetrics(right);
		doubleMetrics.put("plannedMinusLeftRows", leftRows);
		doubleMetrics.put("plannedMinusLeftWorkRows", leftWorkRows);
		doubleMetrics.put("plannedMinusRightRows", rightRows);
		doubleMetrics.put("plannedMinusRightWorkRows", rightWorkRows);
		doubleMetrics.put("plannedMinusOutputRows", outputRows);
		propagateMaterializedFilterWorkRowsPerInvocation(doubleMetrics, left, right);
		doubleMetrics.put(TelemetryMetricNames.PLANNED_CARDINALITY_ROWS, outputRows);
		doubleMetrics.put(TelemetryMetricNames.PLANNED_WORK_ROWS, workRows);
		doubleMetrics.put(TelemetryMetricNames.PLANNED_COST_FINAL_ROWS, outputRows);
		doubleMetrics.put(TelemetryMetricNames.PLANNED_COST_WORK_ROWS, workRows);
		doubleMetrics.put(TelemetryMetricNames.PLANNED_OBJECTIVE_SCORE, workRows);

		return Optional.of(new FactorCostEstimate(workRows, outputRows, stringMetrics, doubleMetrics, false,
				false, 0, 0, Double.NaN, true, false));
	}

	private FactorCostEstimate omniMinusAntiJoinFactorCost(FactorCostEstimate left,
			OmniCorrelatedProbeEstimate omniEstimate, Set<String> sharedBindings) {
		double leftRows = left.getOutputRows();
		double leftWorkRows = left.getWorkRows();
		if (!isFiniteNonNegative(leftWorkRows)) {
			leftWorkRows = leftRows;
		}
		double probeWorkRows = Math.max(1.0d, Math.max(omniEstimate.probeRows(), omniEstimate.matchedRows()));
		double outputRows = Math.min(leftRows, omniEstimate.outputRows());
		double workRows = Math.max(outputRows, leftWorkRows + probeWorkRows);

		Map<String, String> stringMetrics = new HashMap<>(left.getStringMetrics());
		String leftSource = stringMetrics.get(TelemetryMetricNames.PLANNED_ESTIMATE_SOURCE);
		if (leftSource != null) {
			stringMetrics.put("plannedMinusLeftBaseEstimateSource", leftSource);
		}
		stringMetrics.put(TelemetryMetricNames.PLANNED_ESTIMATE_SOURCE, "omni-anti-join");
		stringMetrics.put("plannedMinusExecution", "omni-anti-probe");
		stringMetrics.put("plannedMinusSharedBindings", new TreeSet<>(sharedBindings).toString());

		Map<String, Double> doubleMetrics = parentDoubleMetrics(left);
		doubleMetrics.put("plannedMinusLeftRows", leftRows);
		doubleMetrics.put("plannedMinusLeftWorkRows", leftWorkRows);
		doubleMetrics.put("plannedMinusRightRows", omniEstimate.probeRows());
		doubleMetrics.put("plannedMinusRightWorkRows", probeWorkRows);
		doubleMetrics.put("plannedMinusOutputRows", outputRows);
		doubleMetrics.put("plannedAntiExistsProbeWorkRows", probeWorkRows);
		doubleMetrics.put("plannedAntiExistsProbeOutputRows", omniEstimate.probeRows());
		doubleMetrics.put("plannedAntiExistsMatchedRows", omniEstimate.matchedRows());
		doubleMetrics.put("plannedAntiExistsInputRows", omniEstimate.inputRows());
		doubleMetrics.put("plannedAntiExistsSharedBindingCount", (double) sharedBindings.size());
		doubleMetrics.put("plannedOmniAntiInputWitnesses", (double) omniEstimate.inputWitnesses());
		doubleMetrics.put("plannedOmniAntiProbeWitnesses", (double) omniEstimate.matchedWitnesses());
		doubleMetrics.put("plannedOmniAntiMatchedWitnesses", (double) omniEstimate.matchedWitnesses());
		doubleMetrics.put("plannedOmniAntiTupleKeyWitnesses", omniEstimate.keyWidth() == 2
				? (double) omniEstimate.inputWitnesses()
				: 0.0d);
		doubleMetrics.put("plannedOmniAntiSamplingProbability", omniEstimate.samplingProbability());
		doubleMetrics.put("plannedOmniAntiConfidence", omniEstimate.confidence());
		doubleMetrics.put("plannedOmniAntiProbeKeyWidth", (double) omniEstimate.keyWidth());
		doubleMetrics.put("plannedOmniAntiSketchZero", outputRows == 0.0d && !omniEstimate.exactZero() ? 1.0d
				: 0.0d);
		doubleMetrics.put(TelemetryMetricNames.PLANNED_CARDINALITY_ROWS, outputRows);
		doubleMetrics.put(TelemetryMetricNames.PLANNED_WORK_ROWS, workRows);
		doubleMetrics.put(TelemetryMetricNames.PLANNED_COST_FINAL_ROWS,
				outputRows == 0.0d && !omniEstimate.exactZero() ? 1.0d : outputRows);
		doubleMetrics.put(TelemetryMetricNames.PLANNED_COST_WORK_ROWS, workRows);
		doubleMetrics.put(TelemetryMetricNames.PLANNED_OBJECTIVE_SCORE, workRows);
		return new FactorCostEstimate(workRows, outputRows, stringMetrics, doubleMetrics, false, false, 0, 0,
				Double.NaN, true, false);
	}

	private double optionalBridgeProductRows(LeftJoin leftJoin, double leftRows) {
		double plannedRows = leftJoin.getDoubleMetricPlanned("plannedOptionalBridgeProductRows");
		if (isFiniteNonNegative(plannedRows)) {
			return plannedRows;
		}
		OptionalBridgeProductEstimate estimate = estimateOptionalBridgeProduct(leftJoin.getLeftArg(),
				leftJoin.getRightArg(), leftRows);
		return estimate == null ? Double.NaN : estimate.productRows();
	}

	private JoinFactorCostModel.CostContext optionalRightCostContext(JoinFactorCostModel.CostContext context,
			TupleExpr leftArg, TupleExpr rightArg, double leftRows, Set<String> sharedBindings) {
		Map<String, Set<Value>> finiteBindingValues = new HashMap<>(context.getFiniteBindingValues());
		addFiniteBindingValues(finiteBindingValues, leftArg);
		BridgeProductPrefixFactors prefixFactors = bridgeProductPrefixFactors(leftArg, rightArg);
		List<TupleExpr> rightPrefixFactors = prefixFactors == null ? List.of() : prefixFactors.factors();
		if (context.hasCurrentlyBoundVarMask()) {
			long rightBoundMask = context.getCurrentlyBoundVarMask()
					| bindingMask(context.getVariableNames(), sharedBindings);
			return JoinFactorCostModel.CostContext.forOptimization(context.getVariableNames(), rightBoundMask,
					leftRows, Double.NaN, true, context.shouldCollectMetrics(), finiteBindingValues,
					rightPrefixFactors)
					.withEstimationTier(context.getEstimationTier());
		}
		Set<String> rightBoundVars = unionBindingNames(context.getCurrentlyBoundVars(), sharedBindings);
		return JoinFactorCostModel.CostContext.forOptimization(rightBoundVars, leftRows, Double.NaN, true,
				context.shouldCollectMetrics(), finiteBindingValues, rightPrefixFactors)
				.withEstimationTier(context.getEstimationTier());
	}

	private FactorCostEstimate accountNestedInvocationWork(TupleExpr factor, FactorCostEstimate estimate,
			JoinFactorCostModel.CostContext context) {
		double outerPrefixRows = context.getOuterPrefixRows();
		double finitePrefixRows = repeatedInvocationPrefixRows(context);
		if (isFiniteNonNegative(finitePrefixRows)) {
			outerPrefixRows = isFiniteNonNegative(outerPrefixRows) ? Math.max(outerPrefixRows, finitePrefixRows)
					: finitePrefixRows;
		}
		if (!isFiniteNonNegative(outerPrefixRows) || outerPrefixRows <= 1.0d) {
			if (estimateTraceEnabled()) {
				traceEstimate("nested-cost-skip", factor, context,
						"reason=outer-prefix rows=" + estimateTraceRows(outerPrefixRows));
			}
			return estimate;
		}
		double workRows = estimate.getWorkRows();
		if (!isFiniteNonNegative(workRows)) {
			if (estimateTraceEnabled()) {
				traceEstimate("nested-cost-skip", factor, context,
						"reason=base-work rows=" + estimateTraceRows(workRows));
			}
			return estimate;
		}
		if (exactStatementLookupAlreadyCostsRepeatedInvocations(estimate, outerPrefixRows)) {
			if (estimateTraceEnabled()) {
				traceEstimate("nested-cost-keep-repeated-exact-statement", factor, context,
						estimateTraceEstimate(estimate));
			}
			return estimate;
		}
		double perInvocationWorkRows = workRows;
		double accessRows = estimate.getAccessRowsBeforeFilter();
		if (isFiniteNonNegative(accessRows)) {
			perInvocationWorkRows = Math.max(perInvocationWorkRows, accessRows);
		}
		boolean lookupUsesOuterBindings = usesOuterBindingsForLookup(factor, estimate, context);
		if (estimate.hasPhysicalAccessPath() && !lookupUsesOuterBindings) {
			if (estimateTraceEnabled()) {
				traceEstimate("nested-cost-uncorrelated-physical-access", factor, context,
						"reason=uncorrelated-physical-access"
								+ ", baseWork=" + estimateTraceRows(workRows)
								+ ", perInvocationWork=" + estimateTraceRows(perInvocationWorkRows)
								+ ", outerPrefixRows=" + estimateTraceRows(outerPrefixRows));
			}
		}
		double distinctLookupBindings = context.getDistinctLookupBindings();
		if (!isFiniteNonNegative(distinctLookupBindings) || distinctLookupBindings <= 0.0d) {
			distinctLookupBindings = lookupDomainDistinctRows(factor, estimate, context);
		}
		double repeatedInvocations = repeatedInvocations(estimate, outerPrefixRows, distinctLookupBindings);
		if (!isFiniteNonNegative(distinctLookupBindings) || distinctLookupBindings <= 0.0d) {
			distinctLookupBindings = repeatedInvocations;
		}
		double multipliedWorkRows = repeatedInvocations * perInvocationWorkRows;
		double nestedWorkRows = isFiniteNonNegative(multipliedWorkRows)
				? Math.max(repeatedInvocations, multipliedWorkRows)
				: Math.max(repeatedInvocations, perInvocationWorkRows);
		double predicateBoundedWorkRows = predicateBoundedRepeatedPrefixWorkRows(factor, estimate, context,
				repeatedInvocations);
		if (isFiniteNonNegative(predicateBoundedWorkRows)) {
			nestedWorkRows = Math.min(nestedWorkRows, predicateBoundedWorkRows);
		}
		double lookupDomainOutputRows = lookupDomainAverageRepeatedOutputRows(factor, estimate, context,
				repeatedInvocations, distinctLookupBindings);
		double nestedOutputRows = estimate.getOutputRows();
		if (isFiniteNonNegative(lookupDomainOutputRows)) {
			nestedOutputRows = lookupDomainOutputRows;
			if (isDirectLookup(estimate) || !hasDuplicateLookupKeyInvocations(repeatedInvocations,
					distinctLookupBindings)) {
				double lookupDomainWorkRows = lookupDomainRepeatedWorkRows(lookupDomainOutputRows,
						repeatedInvocations, estimate);
				if (isFiniteNonNegative(lookupDomainWorkRows)) {
					nestedWorkRows = lookupDomainWorkRows;
				}
			}
		} else if (lookupUsesOuterBindings || !estimate.hasPhysicalAccessPath()) {
			nestedOutputRows = repeatedOutputRows(estimate, repeatedInvocations);
		}
		if (isFiniteNonNegative(nestedOutputRows) && nestedOutputRows > nestedWorkRows) {
			nestedWorkRows = nestedOutputRows;
		}
		if (!isFiniteNonNegative(nestedWorkRows) || nestedWorkRows <= workRows) {
			if (estimateTraceEnabled()) {
				traceEstimate("nested-cost-keep-base", factor, context,
						"baseWork=" + estimateTraceRows(workRows)
								+ ", nestedWork=" + estimateTraceRows(nestedWorkRows)
								+ ", nestedOutput=" + estimateTraceRows(nestedOutputRows)
								+ ", repeatedInvocations=" + estimateTraceRows(repeatedInvocations)
								+ ", distinctLookup=" + estimateTraceRows(distinctLookupBindings)
								+ ", lookupDomainOutput=" + estimateTraceRows(lookupDomainOutputRows));
			}
			return estimate;
		}
		Map<String, Double> doubleMetrics = estimate.getDoubleMetrics();
		if (context.shouldCollectMetrics()) {
			doubleMetrics = new HashMap<>(doubleMetrics);
			doubleMetrics.put(TelemetryMetricNames.PLANNED_WORK_ROWS, nestedWorkRows);
			doubleMetrics.put(PLANNED_REPEATED_INVOCATIONS, repeatedInvocations);
			if (LmdbOperatorFeedbackStats.supportsOperatorFeedback(factor)) {
				doubleMetrics.put(PLANNED_OPERATOR_REPEATED_INVOCATIONS, repeatedInvocations);
			}
			doubleMetrics.putIfAbsent(TelemetryMetricNames.PLANNED_ACCESS_WORK_ROWS, perInvocationWorkRows);
			if (isFiniteNonNegative(lookupDomainOutputRows)) {
				doubleMetrics.put("plannedLookupDomainAverageOutputRows", lookupDomainOutputRows);
			}
			if (isFiniteNonNegative(distinctLookupBindings)) {
				doubleMetrics.put("plannedDistinctLookupBindings", distinctLookupBindings);
			}
		}
		FactorCostEstimate nestedEstimate = new FactorCostEstimate(nestedWorkRows, nestedOutputRows,
				estimate.getStringMetrics(),
				doubleMetrics, estimate.hasPhysicalAccessPath(), estimate.isDirectLookup(),
				estimate.getLookupComponentMask(), estimate.getMissingLookupComponentMask(),
				estimate.getAccessRowsBeforeFilter(), true);
		nestedEstimate = preserveBagEstimate(estimate, nestedEstimate);
		if (estimateTraceEnabled()) {
			traceEstimate("nested-cost-accept", factor, context,
					estimateTraceEstimate(nestedEstimate)
							+ ", baseWork=" + estimateTraceRows(workRows)
							+ ", perInvocationWork=" + estimateTraceRows(perInvocationWorkRows)
							+ ", repeatedInvocations=" + estimateTraceRows(repeatedInvocations)
							+ ", distinctLookup=" + estimateTraceRows(distinctLookupBindings)
							+ ", lookupDomainOutput=" + estimateTraceRows(lookupDomainOutputRows));
		}
		return nestedEstimate;
	}

	private FactorCostEstimate preserveBagEstimate(FactorCostEstimate source, FactorCostEstimate replacement) {
		if (source == null || replacement == null) {
			return replacement;
		}
		return source.getBagEstimate()
				.map(replacement::withBag)
				.orElse(replacement);
	}

	private FactorCostEstimate preserveBagEstimate(FactorCostEstimate source, FactorCostEstimate replacement,
			double rows, double workRows, double confidence, String sourceName, Map<String, Double> metrics,
			boolean preserveFinite) {
		if (source == null || replacement == null) {
			return replacement;
		}
		return source.getBagEstimate()
				.map(bag -> bag.withRowsPreservingEvidence(rows, workRows, confidence, sourceName, metrics,
						preserveFinite))
				.map(replacement::withBag)
				.orElse(replacement);
	}

	private double repeatedInvocationPrefixRows(JoinFactorCostModel.CostContext context) {
		if (context == null || context.getPrefixFactors()
				.isEmpty()) {
			return Double.NaN;
		}
		double prefixRows = estimateFiniteBranchRows(context.getPrefixFactors());
		return isFiniteNonNegative(prefixRows) ? prefixRows : Double.NaN;
	}

	private double lookupDomainRepeatedWorkRows(double lookupDomainOutputRows, double repeatedInvocations,
			FactorCostEstimate estimate) {
		if (!isFiniteNonNegative(lookupDomainOutputRows) || !isFiniteNonNegative(repeatedInvocations)) {
			return Double.NaN;
		}
		double workRows = lookupDomainOutputRows + repeatedInvocations;
		double materializedFilterWorkRows = repeatedMaterializedFilterWorkRows(estimate, repeatedInvocations);
		if (isFiniteNonNegative(materializedFilterWorkRows)) {
			workRows += materializedFilterWorkRows;
		}
		return isFiniteNonNegative(workRows) ? workRows : Double.NaN;
	}

	private double repeatedMaterializedFilterWorkRows(FactorCostEstimate estimate, double repeatedInvocations) {
		double materializedFilterWorkRows = materializedFilterWorkRowsPerInvocation(estimate);
		if (!isFiniteNonNegative(materializedFilterWorkRows) || materializedFilterWorkRows == 0.0d
				|| !isFiniteNonNegative(repeatedInvocations)) {
			return 0.0d;
		}
		double repeatedWorkRows = materializedFilterWorkRows * repeatedInvocations;
		return isFiniteNonNegative(repeatedWorkRows) ? repeatedWorkRows : 0.0d;
	}

	private double perInvocationAccessAndMaterializedFilterWorkRows(FactorCostEstimate estimate,
			double accessWorkRows) {
		if (!isFiniteNonNegative(accessWorkRows)) {
			return accessWorkRows;
		}
		double materializedFilterWorkRows = materializedFilterWorkRowsPerInvocation(estimate);
		if (!isFiniteNonNegative(materializedFilterWorkRows) || materializedFilterWorkRows == 0.0d) {
			return accessWorkRows;
		}
		double workRows = accessWorkRows + materializedFilterWorkRows;
		return isFiniteNonNegative(workRows) ? workRows : accessWorkRows;
	}

	private double materializedFilterWorkRowsPerInvocation(FactorCostEstimate estimate) {
		if (estimate == null) {
			return 0.0d;
		}
		double materializedFilterWorkRows = metric(estimate.getDoubleMetrics(),
				PLANNED_MATERIALIZED_FILTER_WORK_ROWS);
		if (!isFiniteNonNegative(materializedFilterWorkRows) || materializedFilterWorkRows == 0.0d) {
			return 0.0d;
		}
		double repeatedInvocations = metric(estimate.getDoubleMetrics(), PLANNED_REPEATED_INVOCATIONS);
		if (estimate.isRepeatedInvocationsCosted() && isFiniteNonNegative(repeatedInvocations)
				&& repeatedInvocations > 1.0d && materializedFilterWorkRows > repeatedInvocations) {
			double perInvocationRows = materializedFilterWorkRows / repeatedInvocations;
			return isFiniteNonNegative(perInvocationRows) ? perInvocationRows : 0.0d;
		}
		return materializedFilterWorkRows;
	}

	private void propagateMaterializedFilterWorkRowsPerInvocation(Map<String, Double> doubleMetrics,
			FactorCostEstimate left, FactorCostEstimate right) {
		if (doubleMetrics == null) {
			return;
		}
		double workRows = materializedFilterWorkRowsPerInvocation(left)
				+ materializedFilterWorkRowsPerInvocation(right);
		if (isFiniteNonNegative(workRows) && workRows > 0.0d) {
			doubleMetrics.put(PLANNED_MATERIALIZED_FILTER_WORK_ROWS, workRows);
		}
	}

	private double repeatedOutputRows(FactorCostEstimate estimate, double repeatedInvocations) {
		double outputRows = estimate.getOutputRows();
		if (estimate.isDirectLookup()) {
			double perInvocationRows = estimate.getAccessRowsBeforeFilter();
			if (!isFiniteNonNegative(perInvocationRows)) {
				perInvocationRows = estimate.getWorkRows();
			}
			if (isFiniteNonNegative(perInvocationRows)) {
				outputRows = isFiniteNonNegative(outputRows) ? Math.min(outputRows, perInvocationRows)
						: perInvocationRows;
			}
		}
		if (!isFiniteNonNegative(outputRows) || !isFiniteNonNegative(repeatedInvocations)) {
			return outputRows;
		}
		double repeatedOutputRows = outputRows * repeatedInvocations;
		return isFiniteNonNegative(repeatedOutputRows) ? repeatedOutputRows : outputRows;
	}

	private boolean usesOuterBindingsForLookup(TupleExpr factor, FactorCostEstimate estimate,
			JoinFactorCostModel.CostContext context) {
		SketchBasedJoinEstimator.AccessShape accessShape = accessShapeForContext(factor, context);
		if (accessShape == null || estimate == null) {
			return false;
		}
		StatementPattern pattern = accessShape.pattern();
		if (pattern == null && factor instanceof StatementPattern statementPattern) {
			pattern = statementPattern;
		}
		int lookupComponentMask = estimate.getLookupComponentMask();
		if (lookupComponentMask == 0) {
			lookupComponentMask = lookupComponentMaskWithConstants(accessShape, pattern);
		}
		return hasCurrentlyBoundLookupComponent(pattern, lookupComponentMask,
				context.getCurrentlyBoundVars());
	}

	private boolean hasCurrentlyBoundLookupComponent(StatementPattern pattern, int lookupComponentMask,
			Set<String> currentlyBoundVars) {
		return currentlyBoundLookupComponentMask(pattern, lookupComponentMask, currentlyBoundVars) != 0;
	}

	private int currentlyBoundLookupComponentMask(StatementPattern pattern, int lookupComponentMask,
			Set<String> currentlyBoundVars) {
		if (pattern == null || lookupComponentMask == 0) {
			return 0;
		}
		Set<String> boundVars = currentlyBoundVars == null ? Set.of() : currentlyBoundVars;
		int currentlyBoundLookupComponentMask = 0;
		for (Component component : Component.values()) {
			if ((lookupComponentMask & componentBit(component)) == 0) {
				continue;
			}
			Var componentVar = componentVar(pattern, component);
			if (componentVar == null || componentVar.hasValue()) {
				continue;
			}
			String name = componentVar.getName();
			if (name != null && !name.startsWith("_const_") && boundVars.contains(name)) {
				currentlyBoundLookupComponentMask |= componentBit(component);
			}
		}
		return currentlyBoundLookupComponentMask;
	}

	private double lookupDomainAverageRepeatedOutputRows(TupleExpr factor, FactorCostEstimate estimate,
			JoinFactorCostModel.CostContext context, double repeatedInvocations, double distinctLookupBindings) {
		if (!usesPhysicalBoundLookup(estimate) || !isFiniteNonNegative(repeatedInvocations)
				|| !isFiniteNonNegative(distinctLookupBindings) || repeatedInvocations <= 0.0d
				|| distinctLookupBindings <= 0.0d) {
			return Double.NaN;
		}
		SketchBasedJoinEstimator.AccessShape accessShape = accessShapeForContext(factor, context);
		if (accessShape == null) {
			return Double.NaN;
		}
		int lookupComponentMask = estimate.getLookupComponentMask();
		if (lookupComponentMask == 0) {
			lookupComponentMask = lookupComponentMaskWithConstants(accessShape, accessShape.pattern());
		}
		int declaredJoinBoundComponentMask = accessShape.joinBoundComponentMask();
		int derivedJoinBoundComponentMask = currentlyBoundLookupComponentMask(accessShape.pattern(),
				lookupComponentMask,
				context.getCurrentlyBoundVars());
		int joinBoundComponentMask = declaredJoinBoundComponentMask | derivedJoinBoundComponentMask;
		if (joinBoundComponentMask == 0) {
			return Double.NaN;
		}
		double perInvocationRows = estimate.getAccessRowsBeforeFilter();
		if (!estimate.isDirectLookup() && isFiniteNonNegative(perInvocationRows)
				&& perInvocationRows < distinctLookupBindings) {
			return Double.NaN;
		}
		if (isBoundGuardLookup(accessShape.pattern(), context.getCurrentlyBoundVars())) {
			double repeatedRows = repeatedOutputRows(estimate, repeatedInvocations);
			if (!isFiniteNonNegative(repeatedRows)) {
				repeatedRows = repeatedInvocations;
			}
			return Math.min(repeatedRows, repeatedInvocations);
		}
		int domainLookupComponentMask = lookupComponentMask & ~joinBoundComponentMask;
		if (isBoundSingletonDirectLookup(estimate, derivedJoinBoundComponentMask, perInvocationRows,
				domainLookupComponentMask)) {
			double repeatedRows = repeatedOutputRows(estimate, repeatedInvocations);
			if (!isFiniteNonNegative(repeatedRows)) {
				repeatedRows = repeatedInvocations;
			}
			return Math.min(repeatedRows, repeatedInvocations);
		}
		if (domainLookupComponentMask == 0 || domainLookupComponentMask == lookupComponentMask) {
			return Double.NaN;
		}
		double domainRows = accessShape.estimateAccessRows(domainLookupComponentMask);
		if (!isFiniteNonNegative(domainRows) || domainRows <= 0.0d) {
			return Double.NaN;
		}
		double filterMultiplier = accessShape.filterMultiplier();
		if (canApplyFilterAtAccess(accessShape, domainLookupComponentMask)
				&& isFiniteNonNegative(filterMultiplier) && filterMultiplier < 1.0d) {
			domainRows *= filterMultiplier;
		}
		double lookupDomainDistinctRows = lookupDomainDistinctRows(factor, estimate, context);
		boolean hasDerivedContextDistinctLookupBindings = context != null
				&& isPositiveFinite(context.getDistinctLookupBindings())
				&& !context.getPrefixFactors().isEmpty();
		double domainFallbackFanout = domainRows / distinctLookupBindings;
		if (!isPositiveFinite(lookupDomainDistinctRows)
				&& !hasDerivedContextDistinctLookupBindings
				&& estimate.isDirectLookup()
				&& isFiniteNonNegative(perInvocationRows)
				&& perInvocationRows <= 1.0d
				&& distinctLookupBindings >= LARGE_OUTER_LOOKUP_DOMAIN_FALLBACK_DISTINCT_ROWS
				&& domainRows > distinctLookupBindings
				&& (!isFiniteNonNegative(domainFallbackFanout)
						|| domainFallbackFanout < LARGE_OUTER_LOOKUP_DOMAIN_FALLBACK_MIN_FANOUT)) {
			return Double.NaN;
		}
		double distinctLookupDenominator = isPositiveFinite(lookupDomainDistinctRows)
				? Math.max(lookupDomainDistinctRows, distinctLookupBindings)
				: distinctLookupBindings;
		double rowsPerDistinctLookup = domainRows / distinctLookupDenominator;
		if (!isFiniteNonNegative(rowsPerDistinctLookup)) {
			return Double.NaN;
		}
		double repeatedRows = rowsPerDistinctLookup * repeatedInvocations;
		if (estimate.isDirectLookup() && estimate.hasExactOutputRows()) {
			double repeatedPhysicalRows = repeatedOutputRows(estimate, repeatedInvocations);
			if (isFiniteNonNegative(repeatedPhysicalRows) && repeatedRows > repeatedPhysicalRows) {
				repeatedRows = repeatedPhysicalRows;
			}
		}
		if (hasDuplicateLookupKeyInvocations(repeatedInvocations, distinctLookupBindings)
				&& !estimate.isDirectLookup()
				&& isFiniteNonNegative(perInvocationRows)
				&& perInvocationRows > distinctLookupBindings && isFiniteNonNegative(repeatedRows)) {
			double repeatedPhysicalRows = repeatedOutputRows(estimate, repeatedInvocations);
			if (isFiniteNonNegative(repeatedPhysicalRows) && repeatedRows < repeatedPhysicalRows) {
				return Double.NaN;
			}
		}
		return isFiniteNonNegative(repeatedRows) ? repeatedRows : Double.NaN;
	}

	private boolean hasDuplicateLookupKeyInvocations(double repeatedInvocations, double distinctLookupBindings) {
		return isFiniteNonNegative(repeatedInvocations)
				&& isFiniteNonNegative(distinctLookupBindings)
				&& repeatedInvocations > distinctLookupBindings;
	}

	private boolean isBoundSingletonDirectLookup(FactorCostEstimate estimate, int derivedJoinBoundComponentMask,
			double perInvocationRows, int domainLookupComponentMask) {
		return estimate.isDirectLookup()
				&& estimate.hasExactOutputRows()
				&& derivedJoinBoundComponentMask != 0
				&& domainLookupComponentMask != 0
				&& isFiniteNonNegative(perInvocationRows)
				&& perInvocationRows <= 1.0d;
	}

	private double lookupDomainDistinctRows(TupleExpr factor, FactorCostEstimate estimate,
			JoinFactorCostModel.CostContext context) {
		if (!usesPhysicalBoundLookup(estimate) || sketchBasedJoinEstimator == null) {
			return Double.NaN;
		}
		SketchBasedJoinEstimator.AccessShape accessShape = accessShapeForContext(factor, context);
		if (accessShape == null) {
			return Double.NaN;
		}
		int lookupComponentMask = estimate.getLookupComponentMask();
		if (lookupComponentMask == 0) {
			lookupComponentMask = lookupComponentMaskWithConstants(accessShape, accessShape.pattern());
		}
		int declaredJoinBoundComponentMask = accessShape.joinBoundComponentMask();
		int derivedJoinBoundComponentMask = currentlyBoundLookupComponentMask(accessShape.pattern(),
				lookupComponentMask,
				context.getCurrentlyBoundVars());
		int joinBoundComponentMask = declaredJoinBoundComponentMask | derivedJoinBoundComponentMask;
		if (joinBoundComponentMask == 0) {
			return Double.NaN;
		}
		Set<String> joinVarNames = new HashSet<>();
		for (Component component : Component.values()) {
			if ((joinBoundComponentMask & componentBit(component)) == 0) {
				continue;
			}
			Var componentVar = componentVar(accessShape.pattern(), component);
			if (componentVar == null || componentVar.hasValue()) {
				continue;
			}
			String name = componentVar.getName();
			if (name != null && !name.startsWith("_const_")) {
				joinVarNames.add(name);
			}
		}
		if (joinVarNames.size() != 1) {
			if (estimateTraceEnabled()) {
				traceEstimate("lookup-domain-distinct-reject", factor, context,
						"reason=unsupported-join-var-count, joinVars=" + joinVarNames);
			}
			return Double.NaN;
		}
		String joinVarName = joinVarNames.iterator()
				.next();
		double distinctRows = sketchBasedJoinEstimator.estimateJoinVarDistinctRows(factor, joinVarName);
		if (!isPositiveFinite(distinctRows)) {
			if (estimateTraceEnabled()) {
				traceEstimate("lookup-domain-distinct-reject", factor, context,
						"joinVar=" + joinVarName + ", distinctRows=" + estimateTraceRows(distinctRows));
			}
			return Double.NaN;
		}
		if (estimateTraceEnabled()) {
			traceEstimate("lookup-domain-distinct", factor, context,
					"joinVar=" + joinVarName + ", distinctRows=" + estimateTraceRows(distinctRows));
		}
		return distinctRows;
	}

	private boolean usesPhysicalBoundLookup(FactorCostEstimate estimate) {
		return estimate != null && estimate.hasPhysicalAccessPath() && estimate.getLookupComponentMask() != 0;
	}

	private boolean isBoundGuardLookup(StatementPattern pattern, Set<String> currentlyBoundVars) {
		if (pattern == null) {
			return false;
		}
		Set<String> boundVars = currentlyBoundVars == null ? Set.of() : currentlyBoundVars;
		boolean hasVariableComponent = false;
		for (Component component : Component.values()) {
			Var componentVar = componentVar(pattern, component);
			if (componentVar == null || componentVar.getValue() != null) {
				continue;
			}
			String name = componentVar.getName();
			if (name == null || name.startsWith("_const_")) {
				continue;
			}
			hasVariableComponent = true;
			if (!boundVars.contains(name)) {
				return false;
			}
		}
		return hasVariableComponent;
	}

	private double predicateBoundedRepeatedPrefixWorkRows(TupleExpr factor, FactorCostEstimate estimate,
			JoinFactorCostModel.CostContext context, double repeatedInvocations) {
		if (isDirectLookup(estimate) || !isFiniteNonNegative(repeatedInvocations)) {
			return Double.NaN;
		}
		int predicateComponentMask = componentBit(Component.P);
		if ((estimate.getMissingLookupComponentMask() & predicateComponentMask) == 0) {
			return Double.NaN;
		}
		SketchBasedJoinEstimator.AccessShape accessShape = accessShapeForContext(factor, context);
		if (accessShape == null || (accessShape.lookupBoundComponentMask() & predicateComponentMask) == 0) {
			return Double.NaN;
		}
		StatementPattern pattern = accessShape.pattern();
		Var predicateVar = pattern == null ? null : pattern.getPredicateVar();
		if (predicateVar == null || !predicateVar.hasValue()) {
			return Double.NaN;
		}
		double predicateRows = accessShape.estimateAccessRows(predicateComponentMask);
		if (!isFiniteNonNegative(predicateRows)) {
			return Double.NaN;
		}
		double repeatedOutputRows = estimate.getOutputRows() * repeatedInvocations;
		double scanRows = isFiniteNonNegative(repeatedOutputRows)
				? Math.max(predicateRows, repeatedOutputRows)
				: predicateRows;
		return Math.max(repeatedInvocations, scanRows + repeatedInvocations);
	}

	private SketchBasedJoinEstimator.AccessShape accessShapeForContext(TupleExpr factor,
			JoinFactorCostModel.CostContext context) {
		if (sketchBasedJoinEstimator == null) {
			return null;
		}
		if (context.hasCurrentlyBoundVarMask()) {
			return sketchBasedJoinEstimator.accessShapeForJoinOrdering(factor, context.getVariableNames(),
					context.getCurrentlyBoundVarMask());
		}
		return sketchBasedJoinEstimator.accessShapeForJoinOrdering(factor, context.getCurrentlyBoundVars());
	}

	private double repeatedInvocations(FactorCostEstimate estimate, double outerPrefixRows,
			double distinctLookupBindings) {
		return outerPrefixRows;
	}

	private boolean isDirectLookup(FactorCostEstimate estimate) {
		return estimate.isDirectLookup()
				|| "directLookup"
						.equals(estimate.getStringMetrics().get(TelemetryMetricNames.PLANNED_INDEX_ACCESS_MODE));
	}

