	private Optional<FactorCostEstimate> estimateLmdbFactorCostUncached(TupleExpr factor,
			Set<String> currentlyBoundVars, double knownOutputRows, boolean collectMetrics,
			Map<String, Set<Value>> finiteBindingValues, JoinFactorCostModel.EstimationTier estimationTier) {
		return estimateLmdbFactorCostUncached(factor, currentlyBoundVars, knownOutputRows, collectMetrics,
				finiteBindingValues, estimationTier, null);
	}

	private Optional<FactorCostEstimate> estimateLmdbFactorCostUncached(TupleExpr factor,
			Set<String> currentlyBoundVars, double knownOutputRows, boolean collectMetrics,
			Map<String, Set<Value>> finiteBindingValues, JoinFactorCostModel.EstimationTier estimationTier,
			RequestedAccessPath requestedAccessPath) {
		Set<String> boundVars = currentlyBoundVars == null ? Set.of() : currentlyBoundVars;
		if (factor instanceof Join join) {
			return estimateJoinFactorCost(join, boundVars);
		}
		Optional<FactorCostEstimate> existsFilterEstimate = estimateCorrelatedExistsFilterFactorCost(factor,
				boundVars, knownOutputRows, collectMetrics, finiteBindingValues, estimationTier);
		if (existsFilterEstimate.isPresent()) {
			return existsFilterEstimate;
		}
		Optional<FactorCostEstimate> antiExistsFilterEstimate = estimateCorrelatedAntiExistsFilterFactorCost(factor,
				boundVars, knownOutputRows, collectMetrics, finiteBindingValues, estimationTier);
		if (antiExistsFilterEstimate.isPresent()) {
			return antiExistsFilterEstimate;
		}
		Optional<FactorCostEstimate> rowPreservingSubplanEstimate = estimateRowPreservingSubplanFactorCost(factor,
				boundVars, knownOutputRows, collectMetrics, finiteBindingValues, estimationTier,
				requestedAccessPath);
		if (rowPreservingSubplanEstimate.isPresent()) {
			return rowPreservingSubplanEstimate;
		}
		Optional<FactorCostEstimate> assignmentEstimate = estimateBindingSetAssignmentFactorCost(factor,
				knownOutputRows);
		if (assignmentEstimate.isPresent()) {
			return assignmentEstimate;
		}
		Optional<FactorCostEstimate> propertyPathEstimate = estimatePropertyPathFactorCost(factor, boundVars,
				collectMetrics);
		if (propertyPathEstimate.isPresent()) {
			return propertyPathEstimate;
		}
		double outputRows = isFiniteNonNegative(knownOutputRows) ? knownOutputRows
				: estimateFactorOutputRows(factor, boundVars);
		if (!Double.isFinite(outputRows) || outputRows < 0.0d) {
			return Optional.empty();
		}

		SketchBasedJoinEstimator.AccessShape accessShape = accessShapeForJoinOrdering(factor, boundVars,
				estimationTier);
		if (requestedAccessPath == null) {
			Optional<FactorCostEstimate> finiteLookupEstimate = estimateFiniteBindingLookupCost(factor, accessShape,
					outputRows, finiteBindingValues, collectMetrics);
			if (finiteLookupEstimate.isPresent()) {
				return finiteLookupEstimate;
			}
		}
		Optional<FactorCostEstimate> estimate = estimateLmdbFactorCost(outputRows, accessShape, collectMetrics,
				requestedAccessPath);
		estimate = accountMaterializedFilterEvaluationWork(factor, estimate, collectMetrics);
		return attachSketchBagEstimate(factor, boundVars, estimate);
	}

